//
//  SpeedDialButton.swift
//  Inlay — component
//
//  A floating action button (FAB) that expands into a fan of mini action
//  buttons with a staggered spring, optional labels that slide + fade in
//  beside each action, a rotating main icon (e.g. plus → ×), and an optional
//  dimmed backdrop. Tapping an action or the backdrop collapses it.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `SpeedDialButton.Configuration`.
//
//      let fab = SpeedDialButton(
//          mainIcon: UIImage(systemName: "plus"),
//          actions: [
//              .init(icon: UIImage(systemName: "camera.fill"), title: "Photo") { print("photo") },
//              .init(icon: UIImage(systemName: "mic.fill"),    title: "Audio") { print("audio") },
//              .init(icon: UIImage(systemName: "doc.fill"),    title: "File")  { print("file") },
//          ]
//      )
//      view.addSubview(fab)
//      NSLayoutConstraint.activate([
//          fab.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -20),
//          fab.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20),
//      ])
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class SpeedDialButton: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Direction the action buttons fan out from the FAB.
        var expandDirection: Direction = .up
        /// Fill color of the main FAB.
        var mainColor: UIColor = .tintColor
        /// Tint of the main FAB's icon.
        var mainIconColor: UIColor = .white
        /// Fill color of each action button.
        var actionColor: UIColor = .secondarySystemBackground
        /// Tint of each action button's icon.
        var actionIconColor: UIColor = .label
        /// Diameter of the main FAB.
        var mainSize: CGFloat = 56
        /// Diameter of each action button.
        var actionSize: CGFloat = 46
        /// Gap between successive buttons along the expand axis.
        var spacing: CGFloat = 14
        /// Whether labels appear beside actions (requires `Action.title`).
        var showsLabels: Bool = true
        /// Background of the label chip.
        var labelBackground: UIColor = .systemBackground
        /// Text color of the label chip.
        var labelTextColor: UIColor = .label
        /// Whether a dimmed backdrop appears behind the expanded actions.
        var backdropDim: Bool = true
        /// Color of the backdrop dim.
        var backdropColor: UIColor = .black
        /// Peak alpha of the backdrop when fully expanded.
        var backdropAlpha: CGFloat = 0.28
        /// Degrees the main icon rotates on expand (e.g. 45 → plus to ×).
        var rotatesMainIconOnExpand: CGFloat = 45
        /// Spring used for every transition. (Shared design token.)
        var animation: Inlay.Spring = .playful
        /// Per-item delay so actions cascade out instead of moving in unison.
        var staggerDelay: TimeInterval = 0.04
        /// Light haptic on expand/collapse and action tap.
        var hapticsEnabled: Bool = true

        /// Direction the actions fan out from the FAB.
        enum Direction {
            case up, down, left, right

            /// Unit offset applied per step along the expand axis.
            var unitOffset: CGPoint {
                switch self {
                case .up:    return CGPoint(x: 0, y: -1)
                case .down:  return CGPoint(x: 0, y: 1)
                case .left:  return CGPoint(x: -1, y: 0)
                case .right: return CGPoint(x: 1, y: 0)
                }
            }

            /// Whether the axis is vertical (labels sit horizontally beside the action).
            var isVertical: Bool { self == .up || self == .down }
        }

        static let `default` = Configuration()
    }

    // MARK: - Action

    /// A single mini action revealed on expand. Provide an SF Symbol (or any
    /// image), an optional label, and a closure to run on tap.
    struct Action {
        let icon: UIImage?
        let title: String?
        let onTap: () -> Void

        init(icon: UIImage?, title: String? = nil, onTap: @escaping () -> Void) {
            self.icon = icon
            self.title = title
            self.onTap = onTap
        }
    }

    // MARK: - Public state

    /// Expanded state. Setting it animates the transition.
    var isExpanded: Bool {
        get { _isExpanded }
        set {
            guard newValue != _isExpanded else { return }
            _isExpanded = newValue
            applyExpanded(newValue, animated: true)
        }
    }

    /// Toggle expansion, optionally without animation.
    func setExpanded(_ expanded: Bool, animated: Bool) {
        guard expanded != _isExpanded else { return }
        _isExpanded = expanded
        applyExpanded(expanded, animated: animated)
    }

    // MARK: - Private state

    private let configuration: Configuration
    private let actions: [Action]
    private let mainIcon: UIImage?

    private let mainButton = UIButton(type: .custom)
    private let backdrop = UIView()
    private var actionViews: [ActionView] = []
    private var _isExpanded = false

    // MARK: - Init

    init(mainIcon: UIImage?, actions: [Action], configuration: Configuration = .default) {
        self.configuration = configuration
        self.actions = actions
        self.mainIcon = mainIcon
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        self.actions = []
        self.mainIcon = nil
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false
        // Actions extend beyond the FAB bounds, so never clip.
        clipsToBounds = false

        // Self sizes to the main FAB.
        NSLayoutConstraint.activate([
            widthAnchor.constraint(equalToConstant: configuration.mainSize),
            heightAnchor.constraint(equalToConstant: configuration.mainSize),
        ])

        setUpBackdrop()
        setUpActions()
        setUpMainButton()
    }

    private func setUpBackdrop() {
        backdrop.backgroundColor = configuration.backdropColor
        backdrop.alpha = 0
        backdrop.isUserInteractionEnabled = false
        backdrop.isHidden = !configuration.backdropDim
        addSubview(backdrop)

        let tap = UITapGestureRecognizer(target: self, action: #selector(handleBackdropTap))
        backdrop.addGestureRecognizer(tap)
    }

    private func setUpActions() {
        for action in actions {
            let view = ActionView(
                action: action,
                configuration: configuration
            )
            view.onTap = { [weak self] in self?.handleActionTap(action) }
            // Added above the backdrop, below the main button (added last).
            addSubview(view)
            actionViews.append(view)
            // Start collapsed: centered on the FAB, hidden.
            view.frame = collapsedFrame(for: view)
            view.alpha = 0
            view.isUserInteractionEnabled = false
        }
    }

    private func setUpMainButton() {
        mainButton.translatesAutoresizingMaskIntoConstraints = false
        mainButton.backgroundColor = configuration.mainColor
        mainButton.tintColor = configuration.mainIconColor
        mainButton.setImage(
            mainIcon?.withRenderingMode(.alwaysTemplate),
            for: .normal
        )
        mainButton.layer.cornerRadius = configuration.mainSize / 2
        mainButton.layer.cornerCurve = .continuous

        // Shadow on the FAB; the button itself does not clip.
        mainButton.layer.shadowColor = UIColor.black.cgColor
        mainButton.layer.shadowOpacity = 0.25
        mainButton.layer.shadowRadius = 12
        mainButton.layer.shadowOffset = CGSize(width: 0, height: 6)

        mainButton.addTarget(self, action: #selector(mainTouchDown), for: .touchDown)
        mainButton.addTarget(
            self,
            action: #selector(mainTouchUp),
            for: [.touchUpInside, .touchUpOutside, .touchCancel]
        )
        mainButton.addTarget(self, action: #selector(toggle), for: .touchUpInside)

        addSubview(mainButton)
        NSLayoutConstraint.activate([
            mainButton.topAnchor.constraint(equalTo: topAnchor),
            mainButton.bottomAnchor.constraint(equalTo: bottomAnchor),
            mainButton.leadingAnchor.constraint(equalTo: leadingAnchor),
            mainButton.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])
    }

    // MARK: - Hit testing (actions live outside our bounds)

    override func point(inside point: CGPoint, with event: UIEvent?) -> Bool {
        if super.point(inside: point, with: event) { return true }
        // When expanded, the backdrop + action views extend past our bounds.
        for subview in subviews where !subview.isHidden && subview.alpha > 0.01 {
            let converted = convert(point, to: subview)
            if subview.point(inside: converted, with: event) { return true }
        }
        return false
    }

    // MARK: - Geometry

    /// Frame for an action when collapsed: centered behind the FAB.
    private func collapsedFrame(for view: ActionView) -> CGRect {
        let size = view.intrinsicContentSize
        let center = CGPoint(x: bounds.midX, y: bounds.midY)
        return CGRect(
            x: center.x - size.width / 2,
            y: center.y - size.height / 2,
            width: size.width,
            height: size.height
        )
    }

    /// Frame for an action when expanded at the given index.
    private func expandedFrame(for view: ActionView, at index: Int) -> CGRect {
        let size = view.intrinsicContentSize
        let unit = configuration.expandDirection.unitOffset
        let step = configuration.actionSize + configuration.spacing
        let distance = configuration.mainSize / 2
            + configuration.spacing
            + configuration.actionSize / 2
            + CGFloat(index) * step

        // Anchor on the action *button* center (not the whole chip), so the
        // dots align in a straight line regardless of label width.
        let fabCenter = CGPoint(x: bounds.midX, y: bounds.midY)
        let buttonCenter = CGPoint(
            x: fabCenter.x + unit.x * distance,
            y: fabCenter.y + unit.y * distance
        )

        // Position the chip so its action-button portion centers on buttonCenter.
        let buttonHalf = configuration.actionSize / 2
        var origin: CGPoint
        switch configuration.expandDirection {
        case .up, .down:
            // Button is horizontally centered in the chip.
            origin = CGPoint(
                x: buttonCenter.x - size.width / 2,
                y: buttonCenter.y - buttonHalf
            )
        case .right:
            // Action button sits at the leading edge of the chip.
            origin = CGPoint(
                x: buttonCenter.x - buttonHalf,
                y: buttonCenter.y - size.height / 2
            )
        case .left:
            // Action button sits at the trailing edge of the chip.
            origin = CGPoint(
                x: buttonCenter.x + buttonHalf - size.width,
                y: buttonCenter.y - size.height / 2
            )
        }
        return CGRect(origin: origin, size: size)
    }

    // MARK: - Interaction

    @objc private func toggle() {
        isExpanded.toggle()
    }

    @objc private func handleBackdropTap() {
        isExpanded = false
    }

    private func handleActionTap(_ action: Action) {
        fireHaptic()
        action.onTap()
        isExpanded = false
    }

    @objc private func mainTouchDown() {
        Inlay.SpringAnimator.animate(.snappy) {
            self.mainButton.transform = self.mainButton.transform
                .scaledBy(x: 0.9, y: 0.9)
        }
    }

    @objc private func mainTouchUp() {
        Inlay.SpringAnimator.animate(configuration.animation) {
            self.mainButton.transform = self.rotationTransform(for: self.isExpanded)
        }
    }

    // MARK: - Expansion

    private func rotationTransform(for expanded: Bool) -> CGAffineTransform {
        guard expanded else { return .identity }
        let radians = configuration.rotatesMainIconOnExpand * .pi / 180
        return CGAffineTransform(rotationAngle: radians)
    }

    private func fireHaptic() {
        guard configuration.hapticsEnabled else { return }
        UIImpactFeedbackGenerator(style: .light).impactOccurred()
    }

    private func applyExpanded(_ expanded: Bool, animated: Bool) {
        layoutIfNeeded()
        fireHaptic()

        if expanded {
            // Make sure action views start from the collapsed pose.
            for view in actionViews where view.alpha < 0.01 {
                view.frame = collapsedFrame(for: view)
            }
        }

        // Backdrop.
        if configuration.backdropDim {
            let targetAlpha = expanded ? configuration.backdropAlpha : 0
            let backdropBlock = { self.backdrop.alpha = targetAlpha }
            if animated {
                Inlay.SpringAnimator.animate(configuration.animation, backdropBlock)
            } else {
                backdropBlock()
            }
            backdrop.isUserInteractionEnabled = expanded
            if expanded { bringBackdropForward() }
        }

        // Main icon rotation.
        let rotationBlock = {
            self.mainButton.transform = self.rotationTransform(for: expanded)
        }
        if animated {
            Inlay.SpringAnimator.animate(configuration.animation, rotationBlock)
        } else {
            rotationBlock()
        }

        // Staggered actions. On collapse the order reverses so the closest
        // action retracts last.
        let count = actionViews.count
        for (index, view) in actionViews.enumerated() {
            view.isUserInteractionEnabled = expanded
            let staggerIndex = expanded ? index : (count - 1 - index)
            let delay = configuration.staggerDelay * Double(staggerIndex)

            let target = expanded
                ? expandedFrame(for: view, at: index)
                : collapsedFrame(for: view)
            let targetAlpha: CGFloat = expanded ? 1 : 0

            let animateBlock = {
                Inlay.SpringAnimator.animate(self.configuration.animation) {
                    view.frame = target
                    view.alpha = targetAlpha
                    view.setLabelRevealed(expanded)
                }
            }

            if animated {
                if delay > 0 {
                    DispatchQueue.main.asyncAfter(deadline: .now() + delay, execute: animateBlock)
                } else {
                    animateBlock()
                }
            } else {
                view.frame = target
                view.alpha = targetAlpha
                view.setLabelRevealed(expanded)
            }
        }
    }

    /// Keep the backdrop directly under the actions + FAB.
    private func bringBackdropForward() {
        bringSubviewToFront(backdrop)
        for view in actionViews { bringSubviewToFront(view) }
        bringSubviewToFront(mainButton)
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        // Expand the backdrop to cover the whole window so the dim reads.
        if let host = window {
            let frameInSelf = host.convert(host.bounds, to: self)
            backdrop.frame = frameInSelf
        }
        // Keep collapsed actions pinned under the FAB before first expand.
        if !isExpanded {
            for view in actionViews where view.alpha < 0.01 {
                view.frame = collapsedFrame(for: view)
            }
        }
        // FAB shadow path for crisp, performant shadows.
        mainButton.layer.shadowPath = UIBezierPath(
            ovalIn: mainButton.bounds
        ).cgPath
    }

    // MARK: - ActionView

    /// A single action: a circular button plus an optional sliding label chip.
    private final class ActionView: UIView {

        var onTap: (() -> Void)?

        private let configuration: Configuration
        private let button = UIButton(type: .custom)
        private let label = UILabel()
        private let labelChip = UIView()
        private let hasLabel: Bool
        private let isVertical: Bool

        // Label slides in from the FAB side; this is its hidden offset.
        private var labelHiddenTransform: CGAffineTransform = .identity

        init(action: Action, configuration: Configuration) {
            self.configuration = configuration
            self.isVertical = configuration.expandDirection.isVertical
            self.hasLabel = configuration.showsLabels
                && (action.title?.isEmpty == false)
                && !isVertical // labels render beside left/right axes cleanly
            super.init(frame: .zero)
            setUp(action: action)
        }

        required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

        private func setUp(action: Action) {
            isUserInteractionEnabled = true
            clipsToBounds = false

            // Circular button.
            button.frame = CGRect(
                x: 0, y: 0,
                width: configuration.actionSize,
                height: configuration.actionSize
            )
            button.backgroundColor = configuration.actionColor
            button.tintColor = configuration.actionIconColor
            button.setImage(
                action.icon?.withRenderingMode(.alwaysTemplate),
                for: .normal
            )
            button.layer.cornerRadius = configuration.actionSize / 2
            button.layer.cornerCurve = .continuous
            button.layer.shadowColor = UIColor.black.cgColor
            button.layer.shadowOpacity = 0.18
            button.layer.shadowRadius = 8
            button.layer.shadowOffset = CGSize(width: 0, height: 3)
            button.addTarget(self, action: #selector(tapped), for: .touchUpInside)
            addSubview(button)

            if hasLabel {
                labelChip.backgroundColor = configuration.labelBackground
                labelChip.layer.cornerRadius = 8
                labelChip.layer.cornerCurve = .continuous
                labelChip.layer.shadowColor = UIColor.black.cgColor
                labelChip.layer.shadowOpacity = 0.15
                labelChip.layer.shadowRadius = 6
                labelChip.layer.shadowOffset = CGSize(width: 0, height: 2)
                labelChip.isUserInteractionEnabled = false

                label.text = action.title
                label.font = .preferredFont(forTextStyle: .subheadline)
                label.adjustsFontForContentSizeCategory = true
                label.textColor = configuration.labelTextColor
                label.translatesAutoresizingMaskIntoConstraints = false

                labelChip.addSubview(label)
                NSLayoutConstraint.activate([
                    label.leadingAnchor.constraint(equalTo: labelChip.leadingAnchor, constant: 10),
                    label.trailingAnchor.constraint(equalTo: labelChip.trailingAnchor, constant: -10),
                    label.topAnchor.constraint(equalTo: labelChip.topAnchor, constant: 6),
                    label.bottomAnchor.constraint(equalTo: labelChip.bottomAnchor, constant: -6),
                ])
                addSubview(labelChip)
            }

            layoutContents()
        }

        @objc private func tapped() { onTap?() }

        // MARK: Sizing

        private var labelSize: CGSize {
            guard hasLabel else { return .zero }
            label.sizeToFit()
            return CGSize(
                width: label.intrinsicContentSize.width + 20,
                height: max(configuration.actionSize, label.intrinsicContentSize.height + 12)
            )
        }

        override var intrinsicContentSize: CGSize {
            let action = configuration.actionSize
            guard hasLabel else { return CGSize(width: action, height: action) }
            let chip = labelSize
            let gap: CGFloat = 10
            // Button + gap + label, laid out along the horizontal axis.
            return CGSize(
                width: action + gap + chip.width,
                height: max(action, chip.height)
            )
        }

        private func layoutContents() {
            let total = intrinsicContentSize
            frame = CGRect(origin: frame.origin, size: total)

            let action = configuration.actionSize
            let gap: CGFloat = 10

            switch configuration.expandDirection {
            case .right:
                // Button leading, label trailing.
                button.frame = CGRect(
                    x: 0, y: (total.height - action) / 2,
                    width: action, height: action
                )
                if hasLabel {
                    let chip = labelSize
                    labelChip.frame = CGRect(
                        x: action + gap,
                        y: (total.height - chip.height) / 2,
                        width: chip.width, height: chip.height
                    )
                    labelHiddenTransform = CGAffineTransform(translationX: -12, y: 0)
                }
            case .left:
                // Label leading, button trailing.
                button.frame = CGRect(
                    x: total.width - action,
                    y: (total.height - action) / 2,
                    width: action, height: action
                )
                if hasLabel {
                    let chip = labelSize
                    labelChip.frame = CGRect(
                        x: 0,
                        y: (total.height - chip.height) / 2,
                        width: chip.width, height: chip.height
                    )
                    labelHiddenTransform = CGAffineTransform(translationX: 12, y: 0)
                }
            case .up, .down:
                // Vertical axes: just the button, centered.
                button.frame = CGRect(
                    x: (total.width - action) / 2,
                    y: (total.height - action) / 2,
                    width: action, height: action
                )
            }

            if hasLabel {
                labelChip.alpha = 0
                labelChip.transform = labelHiddenTransform
            }
        }

        /// Slide + fade the label as the action reveals/hides.
        func setLabelRevealed(_ revealed: Bool) {
            guard hasLabel else { return }
            labelChip.alpha = revealed ? 1 : 0
            labelChip.transform = revealed ? .identity : labelHiddenTransform
        }
    }
}

//
//  FloatingToolbar.swift
//  Inlay — component
//
//  A floating, pill-shaped toolbar with a glass (blur) or solid background,
//  a spring entrance animation, tactile press feedback, and an optional
//  selection highlight.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `FloatingToolbar.Configuration`.
//
//      let toolbar = FloatingToolbar(items: [
//          .init(icon: UIImage(systemName: "house.fill"))     { print("home") },
//          .init(icon: UIImage(systemName: "magnifyingglass")) { print("search") },
//          .init(icon: UIImage(systemName: "bell.fill"))       { print("alerts") },
//          .init(icon: UIImage(systemName: "person.fill"))     { print("profile") },
//      ])
//      view.addSubview(toolbar)
//      NSLayoutConstraint.activate([
//          toolbar.centerXAnchor.constraint(equalTo: view.centerXAnchor),
//          toolbar.bottomAnchor.constraint(
//              equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16),
//      ])
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class FloatingToolbar: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Tint for item icons and the selection highlight.
        var accentColor: UIColor = .tintColor
        /// Background appearance.
        var background: Background = .glass(.systemThinMaterial)
        /// Corner radius of the pill. Large values read as fully rounded.
        var cornerRadius: CGFloat = 28
        /// Horizontal padding inside the bar.
        var horizontalInset: CGFloat = 16
        /// Spacing between items.
        var itemSpacing: CGFloat = 8
        /// Tappable size of each item.
        var itemSize: CGFloat = 44
        /// Spring used for entrance + press feedback. (Shared design token.)
        var animation: Inlay.Spring = .lively
        /// Whether a highlight follows the last-tapped item.
        var showsSelection: Bool = true
        /// Haptic feedback on tap.
        var hapticsEnabled: Bool = true

        enum Background {
            case glass(UIBlurEffect.Style)
            case solid(UIColor)
        }

        static let `default` = Configuration()
    }

    // MARK: - Item

    /// A single tappable item. Provide an SF Symbol (or any image) and a
    /// closure to run on tap.
    struct Item {
        let icon: UIImage?
        let title: String?
        let onTap: () -> Void

        init(icon: UIImage?, title: String? = nil, onTap: @escaping () -> Void) {
            self.icon = icon
            self.title = title
            self.onTap = onTap
        }
    }

    // MARK: - Private state

    private let configuration: Configuration
    private var items: [Item]
    private let container = UIView()
    private let stack = UIStackView()
    private var backgroundView = UIView()
    private var selectionView: UIView?
    private var buttons: [UIButton] = []
    private var hasAppeared = false

    // MARK: - Init

    init(items: [Item], configuration: Configuration = .default) {
        self.configuration = configuration
        self.items = items
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        self.items = []
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false

        // Outer view carries the shadow and must NOT clip.
        setUpShadow()

        // Inner container clips the corner radius + background.
        container.translatesAutoresizingMaskIntoConstraints = false
        container.layer.cornerRadius = configuration.cornerRadius
        container.layer.cornerCurve = .continuous
        container.clipsToBounds = true
        addSubview(container)
        NSLayoutConstraint.activate([
            container.topAnchor.constraint(equalTo: topAnchor),
            container.bottomAnchor.constraint(equalTo: bottomAnchor),
            container.leadingAnchor.constraint(equalTo: leadingAnchor),
            container.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])

        setUpBackground()
        setUpStack()
        rebuildItems()
        prepareForEntrance()
    }

    private func setUpShadow() {
        layer.shadowColor = UIColor.black.cgColor
        layer.shadowOpacity = 0.18
        layer.shadowRadius = 18
        layer.shadowOffset = CGSize(width: 0, height: 8)
    }

    private func setUpBackground() {
        switch configuration.background {
        case .glass(let style):
            backgroundView = UIVisualEffectView(effect: UIBlurEffect(style: style))
        case .solid(let color):
            let view = UIView()
            view.backgroundColor = color
            backgroundView = view
        }
        backgroundView.translatesAutoresizingMaskIntoConstraints = false
        backgroundView.isUserInteractionEnabled = false
        container.addSubview(backgroundView)
        NSLayoutConstraint.activate([
            backgroundView.topAnchor.constraint(equalTo: container.topAnchor),
            backgroundView.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            backgroundView.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            backgroundView.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])
    }

    private func setUpStack() {
        stack.axis = .horizontal
        stack.alignment = .center
        stack.distribution = .fillEqually
        stack.spacing = configuration.itemSpacing
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.isLayoutMarginsRelativeArrangement = true
        stack.layoutMargins = UIEdgeInsets(
            top: 8,
            left: configuration.horizontalInset,
            bottom: 8,
            right: configuration.horizontalInset
        )
        container.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: container.topAnchor),
            stack.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            stack.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            stack.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])
    }

    // MARK: - Items

    /// Replace the toolbar's items at runtime.
    func setItems(_ items: [Item]) {
        self.items = items
        rebuildItems()
    }

    private func rebuildItems() {
        for view in stack.arrangedSubviews {
            stack.removeArrangedSubview(view)
            view.removeFromSuperview()
        }
        buttons.removeAll()

        for (index, item) in items.enumerated() {
            let button = makeButton(for: item, at: index)
            buttons.append(button)
            stack.addArrangedSubview(button)
        }
    }

    private func makeButton(for item: Item, at index: Int) -> UIButton {
        var config = UIButton.Configuration.plain()
        config.image = item.icon
        config.title = item.title
        config.baseForegroundColor = configuration.accentColor
        config.imagePlacement = .top
        config.imagePadding = 2

        let button = UIButton(configuration: config)
        button.translatesAutoresizingMaskIntoConstraints = false
        button.heightAnchor.constraint(equalToConstant: configuration.itemSize).isActive = true
        button.widthAnchor.constraint(
            greaterThanOrEqualToConstant: configuration.itemSize
        ).isActive = true

        button.addAction(UIAction { [weak self] _ in
            self?.handleTap(at: index, button: button, item: item)
        }, for: .touchUpInside)

        button.addTarget(self, action: #selector(buttonTouchDown(_:)), for: .touchDown)
        button.addTarget(
            self,
            action: #selector(buttonTouchUp(_:)),
            for: [.touchUpInside, .touchUpOutside, .touchCancel]
        )
        return button
    }

    // MARK: - Interaction

    private func handleTap(at index: Int, button: UIButton, item: Item) {
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        if configuration.showsSelection {
            moveSelection(to: button)
        }
        item.onTap()
    }

    @objc private func buttonTouchDown(_ sender: UIButton) {
        Inlay.SpringAnimator.animate(configuration.animation) {
            sender.transform = CGAffineTransform(scaleX: 0.9, y: 0.9)
        }
    }

    @objc private func buttonTouchUp(_ sender: UIButton) {
        Inlay.SpringAnimator.animate(configuration.animation) {
            sender.transform = .identity
        }
    }

    private func moveSelection(to button: UIButton) {
        let pill: UIView
        if let existing = selectionView {
            pill = existing
        } else {
            let view = UIView()
            view.backgroundColor = configuration.accentColor.withAlphaComponent(0.18)
            view.layer.cornerRadius = configuration.itemSize / 2
            view.layer.cornerCurve = .continuous
            view.isUserInteractionEnabled = false
            container.insertSubview(view, belowSubview: stack)
            selectionView = view
            pill = view
        }
        container.layoutIfNeeded()
        let target = button.convert(button.bounds, to: container)
        Inlay.SpringAnimator.animate(configuration.animation) {
            pill.frame = target
        }
    }

    // MARK: - Entrance animation

    private func prepareForEntrance() {
        alpha = 0
        transform = CGAffineTransform(scaleX: 0.8, y: 0.8)
    }

    /// Plays the entrance once. Called automatically when added to a window,
    /// but safe to call manually.
    func playEntrance() {
        guard !hasAppeared else { return }
        hasAppeared = true
        Inlay.SpringAnimator.animate(configuration.animation) {
            self.alpha = 1
            self.transform = .identity
        }
    }

    override func didMoveToWindow() {
        super.didMoveToWindow()
        guard window != nil else { return }
        DispatchQueue.main.async { [weak self] in self?.playEntrance() }
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        // Shadow path tracks the pill shape for crisp, performant shadows.
        layer.shadowPath = UIBezierPath(
            roundedRect: bounds,
            cornerRadius: configuration.cornerRadius
        ).cgPath
    }
}

//
//  HomeTabBar.swift
//  Inlay — component
//
//  A custom bottom tab bar for 3, 4, or 5 tabs (the count equals the number of
//  items you pass). Selecting a tab springs its icon up, tints it with the
//  accent color, and slides an indicator (pill / underline / dot) between tabs.
//  It only emits the selected index — your host swaps the content.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `HomeTabBar.Configuration`.
//
//      let tabBar = HomeTabBar(items: [
//          .init(icon: UIImage(systemName: "house"),
//                selectedIcon: UIImage(systemName: "house.fill"),
//                title: "Home") { print("home") },
//          .init(icon: UIImage(systemName: "magnifyingglass"),
//                title: "Search") { print("search") },
//          .init(icon: UIImage(systemName: "person"),
//                selectedIcon: UIImage(systemName: "person.fill"),
//                title: "Profile") { print("profile") },
//      ])
//      tabBar.onChange = { index in print("selected", index) }
//      view.addSubview(tabBar)
//      NSLayoutConstraint.activate([
//          tabBar.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
//          tabBar.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
//          tabBar.bottomAnchor.constraint(
//              equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -12),
//      ])
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class HomeTabBar: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Whether items show titles beneath their icons.
        var style: Style = .icons
        /// Shape of the sliding indicator behind the selected tab.
        var indicator: Indicator = .pill
        /// Background appearance of the bar.
        var background: Background = .glass(.systemThinMaterial)
        /// Tint applied to the selected icon, title, and indicator.
        var accentColor: UIColor = .tintColor
        /// Tint applied to unselected items.
        var inactiveColor: UIColor = .secondaryLabel
        /// Corner radius of the bar. Large values read as fully rounded.
        var cornerRadius: CGFloat = 28
        /// Height of each tab (the bar's content height).
        var itemHeight: CGFloat = 56
        /// Horizontal padding inside the bar.
        var horizontalInset: CGFloat = 8
        /// Spring used for selection + indicator motion. (Shared design token.)
        var animation: Inlay.Spring = .lively
        /// Haptic feedback on selection.
        var hapticsEnabled: Bool = true

        enum Style {
            case icons
            case iconsAndTitles
        }

        enum Indicator {
            case pill
            case underline
            case dot
        }

        enum Background {
            case glass(UIBlurEffect.Style)
            case solid(UIColor)
        }

        static let `default` = Configuration()
    }

    // MARK: - Item

    /// A single tab. Provide an SF Symbol (or any image), an optional selected
    /// variant, an optional title, and a closure to run when selected.
    struct Item {
        let icon: UIImage?
        let selectedIcon: UIImage?
        let title: String?
        let onSelect: () -> Void

        init(
            icon: UIImage?,
            selectedIcon: UIImage? = nil,
            title: String? = nil,
            onSelect: @escaping () -> Void
        ) {
            self.icon = icon
            self.selectedIcon = selectedIcon
            self.title = title
            self.onSelect = onSelect
        }
    }

    // MARK: - Public API

    /// The currently selected tab. Setting it animates the indicator + icon.
    var selectedIndex: Int {
        get { _selectedIndex }
        set { select(newValue, animated: true, notify: false) }
    }

    /// Called whenever the selection changes (including programmatic changes).
    var onChange: ((Int) -> Void)?

    // MARK: - Private state

    private let configuration: Configuration
    private var items: [Item]
    private let container = UIView()
    private let stack = UIStackView()
    private var backgroundView = UIView()
    private let indicatorView = UIView()
    private var buttons: [TabButton] = []
    private var _selectedIndex = 0
    private var hasLaidOutIndicator = false

    // MARK: - Init

    init(items: [Item], configuration: Configuration = .default) {
        self.configuration = configuration
        self.items = items
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        self.items = []
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false

        // Outer view carries the shadow and must NOT clip.
        setUpShadow()

        // Inner container clips the corner radius + background.
        container.translatesAutoresizingMaskIntoConstraints = false
        container.layer.cornerRadius = configuration.cornerRadius
        container.layer.cornerCurve = .continuous
        container.clipsToBounds = true
        addSubview(container)
        NSLayoutConstraint.activate([
            container.topAnchor.constraint(equalTo: topAnchor),
            container.bottomAnchor.constraint(equalTo: bottomAnchor),
            container.leadingAnchor.constraint(equalTo: leadingAnchor),
            container.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])

        setUpBackground()
        setUpIndicator()
        setUpStack()
        rebuildItems()
        applySelectionAppearance(animated: false)
    }

    private func setUpShadow() {
        layer.shadowColor = UIColor.black.cgColor
        layer.shadowOpacity = 0.18
        layer.shadowRadius = 18
        layer.shadowOffset = CGSize(width: 0, height: 8)
    }

    private func setUpBackground() {
        switch configuration.background {
        case .glass(let style):
            backgroundView = UIVisualEffectView(effect: UIBlurEffect(style: style))
        case .solid(let color):
            let view = UIView()
            view.backgroundColor = color
            backgroundView = view
        }
        backgroundView.translatesAutoresizingMaskIntoConstraints = false
        backgroundView.isUserInteractionEnabled = false
        container.addSubview(backgroundView)
        NSLayoutConstraint.activate([
            backgroundView.topAnchor.constraint(equalTo: container.topAnchor),
            backgroundView.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            backgroundView.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            backgroundView.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])
    }

    private func setUpIndicator() {
        // Placed behind the buttons; moved by animating its frame after layout.
        indicatorView.isUserInteractionEnabled = false
        indicatorView.layer.cornerCurve = .continuous
        switch configuration.indicator {
        case .pill:
            indicatorView.backgroundColor = configuration.accentColor.withAlphaComponent(0.18)
        case .underline, .dot:
            indicatorView.backgroundColor = configuration.accentColor
        }
        container.addSubview(indicatorView)
    }

    private func setUpStack() {
        stack.axis = .horizontal
        stack.alignment = .fill
        stack.distribution = .fillEqually
        stack.spacing = 0
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.isLayoutMarginsRelativeArrangement = true
        stack.layoutMargins = UIEdgeInsets(
            top: 0,
            left: configuration.horizontalInset,
            bottom: 0,
            right: configuration.horizontalInset
        )
        container.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: container.topAnchor),
            stack.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            stack.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            stack.trailingAnchor.constraint(equalTo: container.trailingAnchor),
            container.heightAnchor.constraint(equalToConstant: configuration.itemHeight),
        ])
    }

    // MARK: - Items

    /// Replace the bar's items at runtime.
    func setItems(_ items: [Item]) {
        self.items = items
        if _selectedIndex >= items.count { _selectedIndex = 0 }
        rebuildItems()
        applySelectionAppearance(animated: false)
        hasLaidOutIndicator = false
        setNeedsLayout()
    }

    private func rebuildItems() {
        for view in stack.arrangedSubviews {
            stack.removeArrangedSubview(view)
            view.removeFromSuperview()
        }
        buttons.removeAll()

        let showsTitle = configuration.style == .iconsAndTitles
        for (index, item) in items.enumerated() {
            let button = TabButton(item: item, showsTitle: showsTitle)
            button.addAction(UIAction { [weak self] _ in
                self?.handleTap(at: index)
            }, for: .touchUpInside)
            buttons.append(button)
            stack.addArrangedSubview(button)
        }
    }

    // MARK: - Interaction

    private func handleTap(at index: Int) {
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        select(index, animated: true, notify: true)
        items[index].onSelect()
    }

    private func select(_ index: Int, animated: Bool, notify: Bool) {
        guard index >= 0, index < items.count, index != _selectedIndex else {
            if notify, index == _selectedIndex { onChange?(index) }
            return
        }
        _selectedIndex = index
        applySelectionAppearance(animated: animated)
        moveIndicator(animated: animated)
        onChange?(index)
    }

    private func applySelectionAppearance(animated: Bool) {
        for (index, button) in buttons.enumerated() {
            let isSelected = index == _selectedIndex
            let color = isSelected ? configuration.accentColor : configuration.inactiveColor
            let apply = {
                button.setSelected(isSelected, color: color)
            }
            if animated {
                Inlay.SpringAnimator.animate(configuration.animation, apply)
            } else {
                apply()
            }
        }
    }

    // MARK: - Indicator

    private func moveIndicator(animated: Bool) {
        guard _selectedIndex < buttons.count else { return }
        container.layoutIfNeeded()
        let target = indicatorFrame(for: buttons[_selectedIndex])
        let apply = { self.indicatorView.frame = target }
        if animated {
            Inlay.SpringAnimator.animate(configuration.animation, apply)
        } else {
            apply()
        }
        switch configuration.indicator {
        case .pill:
            indicatorView.layer.cornerRadius = min(target.height, target.width) / 2
        case .underline:
            indicatorView.layer.cornerRadius = target.height / 2
        case .dot:
            indicatorView.layer.cornerRadius = target.height / 2
        }
    }

    private func indicatorFrame(for button: TabButton) -> CGRect {
        let cell = button.convert(button.bounds, to: container)
        switch configuration.indicator {
        case .pill:
            let inset: CGFloat = 6
            return cell.insetBy(dx: inset, dy: inset)
        case .underline:
            let width = min(cell.width * 0.5, 28)
            let height: CGFloat = 3
            return CGRect(
                x: cell.midX - width / 2,
                y: cell.maxY - height - 6,
                width: width,
                height: height
            )
        case .dot:
            let size: CGFloat = 5
            return CGRect(
                x: cell.midX - size / 2,
                y: cell.maxY - size - 7,
                width: size,
                height: size
            )
        }
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        // Shadow path tracks the bar shape for crisp, performant shadows.
        layer.shadowPath = UIBezierPath(
            roundedRect: bounds,
            cornerRadius: configuration.cornerRadius
        ).cgPath

        // Position the indicator once geometry is known (and keep it tracking
        // on rotation / resize), without animating the very first placement.
        if !hasLaidOutIndicator, !buttons.isEmpty {
            hasLaidOutIndicator = true
            moveIndicator(animated: false)
        }
    }

    // MARK: - TabButton

    /// One tappable tab. Nested so it can never collide with another
    /// component's helper types.
    private final class TabButton: UIButton {
        private let iconView = UIImageView()
        private let label = UILabel()
        private let item: Item
        private let showsTitle: Bool

        init(item: Item, showsTitle: Bool) {
            self.item = item
            self.showsTitle = showsTitle
            super.init(frame: .zero)
            setUp()
        }

        required init?(coder: NSCoder) {
            fatalError("init(coder:) has not been implemented")
        }

        private func setUp() {
            iconView.contentMode = .scaleAspectFit
            iconView.translatesAutoresizingMaskIntoConstraints = false
            iconView.isUserInteractionEnabled = false
            iconView.image = item.icon
            iconView.preferredSymbolConfiguration = UIImage.SymbolConfiguration(
                pointSize: 20,
                weight: .semibold
            )

            label.translatesAutoresizingMaskIntoConstraints = false
            label.isUserInteractionEnabled = false
            label.font = .systemFont(ofSize: 11, weight: .medium)
            label.adjustsFontForContentSizeCategory = true
            label.textAlignment = .center
            label.text = item.title
            label.isHidden = !(showsTitle && item.title != nil)

            let group = UIStackView(arrangedSubviews: [iconView, label])
            group.axis = .vertical
            group.alignment = .center
            group.spacing = 2
            group.translatesAutoresizingMaskIntoConstraints = false
            group.isUserInteractionEnabled = false
            addSubview(group)

            NSLayoutConstraint.activate([
                group.centerXAnchor.constraint(equalTo: centerXAnchor),
                group.centerYAnchor.constraint(equalTo: centerYAnchor),
                iconView.heightAnchor.constraint(equalToConstant: 24),
                iconView.widthAnchor.constraint(equalToConstant: 24),
            ])
        }

        func setSelected(_ isSelected: Bool, color: UIColor) {
            iconView.image = isSelected ? (item.selectedIcon ?? item.icon) : item.icon
            iconView.tintColor = color
            label.textColor = color
            // Lift the selected icon slightly for a tactile "pop".
            let lift: CGFloat = isSelected ? -3 : 0
            iconView.transform = CGAffineTransform(translationX: 0, y: lift)
        }
    }
}

//
//  HorizontalScroller.swift
//  Inlay — copy-paste UIKit components for iOS ("shadcn/ui for iOS")
//
//  What it is:
//  A generic, configurable horizontal scrollable list built on UICollectionView
//  with a horizontal flow layout. You supply your own item model type and a
//  cellProvider that returns a UIView per item — HorizontalScroller hosts it,
//  handles selection, optional paging, snap-to-item, peek (sliver of the next
//  item), and a center-focused scale/alpha falloff effect.
//
//  Usage:
//      let colors: [UIColor] = [.systemRed, .systemBlue, .systemGreen]
//      var config = HorizontalScroller<UIColor>.Configuration.default
//      config.itemSize = CGSize(width: 200, height: 120)
//      config.snapsToItems = true
//      config.falloff = true
//      let scroller = HorizontalScroller(items: colors, configuration: config) { color in
//          let v = UIView()
//          v.backgroundColor = color
//          v.layer.cornerRadius = 16
//          v.layer.cornerCurve = .continuous
//          return v
//      }
//      scroller.onSelect = { color, index in print("tapped", index) }
//      view.addSubview(scroller)
//      scroller.translatesAutoresizingMaskIntoConstraints = false
//      NSLayoutConstraint.activate([
//          scroller.leadingAnchor.constraint(equalTo: view.leadingAnchor),
//          scroller.trailingAnchor.constraint(equalTo: view.trailingAnchor),
//          scroller.centerYAnchor.constraint(equalTo: view.centerYAnchor),
//          scroller.heightAnchor.constraint(equalToConstant: 120),
//      ])
//
//  Dependency: none (pure UIKit).
//

import UIKit

final class HorizontalScroller<Item>: UIView,
    UICollectionViewDataSource,
    UICollectionViewDelegateFlowLayout,
    UIScrollViewDelegate {

    // MARK: Configuration

    struct Configuration {
        /// Fixed item size. `nil` enables self-sizing cells
        /// (`estimatedItemSize = UICollectionViewFlowLayout.automaticSize`).
        var itemSize: CGSize?
        /// Spacing between items.
        var spacing: CGFloat
        /// Insets around the scrollable content.
        var sectionInsets: UIEdgeInsets
        /// When true, the collection view pages by its own width.
        var isPagingEnabled: Bool
        /// When true (and not paging), snaps to the nearest item on release.
        var snapsToItems: Bool
        /// Shows a sliver of the neighbouring item by reducing the effective
        /// item width and padding the section so items stay centred.
        var peek: CGFloat
        /// When true, applies a scale + alpha falloff to items as they move
        /// away from the horizontal centre of the scroller.
        var falloff: Bool

        // Computed (not stored) because static stored properties aren't
        // allowed inside a generic type.
        static var `default`: Configuration {
            Configuration(
                itemSize: nil,
                spacing: 12,
                sectionInsets: UIEdgeInsets(top: 0, left: 16, bottom: 0, right: 16),
                isPagingEnabled: false,
                snapsToItems: false,
                peek: 0,
                falloff: false
            )
        }
    }

    // MARK: Public API

    /// Called when an item is selected, with the item and its index.
    var onSelect: ((Item, Int) -> Void)?

    /// Replaces the backing items and reloads.
    func setItems(_ items: [Item]) {
        self.items = items
        collectionView.reloadData()
        collectionView.collectionViewLayout.invalidateLayout()
        applyFalloffIfNeeded()
    }

    // MARK: Stored state

    private var items: [Item]
    private let configuration: Configuration
    private let cellProvider: (Item) -> UIView

    private let layout = UICollectionViewFlowLayout()
    private lazy var collectionView: UICollectionView = {
        let cv = UICollectionView(frame: .zero, collectionViewLayout: layout)
        cv.backgroundColor = .clear
        cv.showsHorizontalScrollIndicator = false
        cv.alwaysBounceHorizontal = true
        cv.decelerationRate = .normal
        cv.translatesAutoresizingMaskIntoConstraints = false
        cv.dataSource = self
        cv.delegate = self
        cv.register(HostCell.self, forCellWithReuseIdentifier: HostCell.reuseID)
        return cv
    }()

    // MARK: Init

    init(items: [Item],
         configuration: Configuration = .default,
         cellProvider: @escaping (Item) -> UIView) {
        self.items = items
        self.configuration = configuration
        self.cellProvider = cellProvider
        super.init(frame: .zero)
        setUp()
    }

    @available(*, unavailable)
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    private func setUp() {
        backgroundColor = .clear

        layout.scrollDirection = .horizontal
        layout.minimumLineSpacing = configuration.spacing
        layout.minimumInteritemSpacing = configuration.spacing
        layout.sectionInset = configuration.sectionInsets
        if configuration.itemSize == nil {
            layout.estimatedItemSize = UICollectionViewFlowLayout.automaticSize
        }

        collectionView.isPagingEnabled = configuration.isPagingEnabled

        addSubview(collectionView)
        NSLayoutConstraint.activate([
            collectionView.leadingAnchor.constraint(equalTo: leadingAnchor),
            collectionView.trailingAnchor.constraint(equalTo: trailingAnchor),
            collectionView.topAnchor.constraint(equalTo: topAnchor),
            collectionView.bottomAnchor.constraint(equalTo: bottomAnchor),
        ])
    }

    override func layoutSubviews() {
        super.layoutSubviews()
        applyFalloffIfNeeded()
    }

    // MARK: Sizing helpers

    /// Effective item width, accounting for peek (a sliver of the next item).
    private func effectiveItemSize(in collectionView: UICollectionView) -> CGSize? {
        guard var size = configuration.itemSize else { return nil }
        if configuration.peek > 0 {
            size.width = max(1, size.width - configuration.peek)
        }
        return size
    }

    // MARK: UICollectionViewDataSource

    func collectionView(_ collectionView: UICollectionView,
                        numberOfItemsInSection section: Int) -> Int {
        items.count
    }

    func collectionView(_ collectionView: UICollectionView,
                        cellForItemAt indexPath: IndexPath) -> UICollectionViewCell {
        let cell = collectionView.dequeueReusableCell(
            withReuseIdentifier: HostCell.reuseID, for: indexPath) as! HostCell
        let item = items[indexPath.item]
        cell.host(cellProvider(item))
        return cell
    }

    // MARK: UICollectionViewDelegateFlowLayout

    func collectionView(_ collectionView: UICollectionView,
                        layout collectionViewLayout: UICollectionViewLayout,
                        sizeForItemAt indexPath: IndexPath) -> CGSize {
        if let size = effectiveItemSize(in: collectionView) {
            return size
        }
        // Self-sizing: provide a reasonable estimate; cells size themselves.
        let height = collectionView.bounds.height
            - configuration.sectionInsets.top
            - configuration.sectionInsets.bottom
        return CGSize(width: 1, height: max(1, height))
    }

    func collectionView(_ collectionView: UICollectionView,
                        layout collectionViewLayout: UICollectionViewLayout,
                        insetForSectionAt section: Int) -> UIEdgeInsets {
        var insets = configuration.sectionInsets
        // With peek + snap, pad the section so the focused item sits centred.
        if configuration.peek > 0,
           let size = configuration.itemSize,
           configuration.snapsToItems || configuration.isPagingEnabled {
            let effectiveWidth = max(1, size.width - configuration.peek)
            let sidePad = max(0, (collectionView.bounds.width - effectiveWidth) / 2)
            insets.left = sidePad
            insets.right = sidePad
        }
        return insets
    }

    // MARK: UICollectionViewDelegate (selection)

    func collectionView(_ collectionView: UICollectionView,
                        didSelectItemAt indexPath: IndexPath) {
        let item = items[indexPath.item]
        onSelect?(item, indexPath.item)
    }

    // MARK: UIScrollViewDelegate

    func scrollViewDidScroll(_ scrollView: UIScrollView) {
        applyFalloffIfNeeded()
    }

    func scrollViewWillEndDragging(_ scrollView: UIScrollView,
                                   withVelocity velocity: CGPoint,
                                   targetContentOffset: UnsafeMutablePointer<CGPoint>) {
        guard configuration.snapsToItems, !configuration.isPagingEnabled else { return }

        let proposedOffsetX = targetContentOffset.pointee.x
        let midX = proposedOffsetX + scrollView.bounds.width / 2

        var bestOffsetX = proposedOffsetX
        var bestDistance = CGFloat.greatestFiniteMagnitude

        for attributes in layout.layoutAttributesForElements(
            in: CGRect(x: targetContentOffset.pointee.x,
                       y: 0,
                       width: scrollView.bounds.width,
                       height: scrollView.bounds.height)) ?? []
        where attributes.representedElementCategory == .cell {
            let distance = abs(attributes.center.x - midX)
            if distance < bestDistance {
                bestDistance = distance
                bestOffsetX = attributes.center.x - scrollView.bounds.width / 2
            }
        }

        let minOffset = -scrollView.contentInset.left
        let maxOffset = max(minOffset,
                            scrollView.contentSize.width
                                - scrollView.bounds.width
                                + scrollView.contentInset.right)
        targetContentOffset.pointee.x = min(max(bestOffsetX, minOffset), maxOffset)
    }

    // MARK: Falloff

    private func applyFalloffIfNeeded() {
        guard configuration.falloff else { return }
        let centerX = collectionView.bounds.midX + collectionView.contentOffset.x
        let maxDistance = max(1, collectionView.bounds.width / 2)

        for cell in collectionView.visibleCells {
            let distance = abs(cell.center.x - centerX)
            let ratio = min(1, distance / maxDistance)
            let scale = 1 - 0.25 * ratio
            cell.transform = CGAffineTransform(scaleX: scale, y: scale)
            cell.alpha = 1 - 0.5 * ratio
        }
    }

    // MARK: HostCell

    private final class HostCell: UICollectionViewCell {
        // Computed (not stored) because static stored properties aren't
        // allowed inside a generic type's nested type.
        static var reuseID: String { "Inlay.HorizontalScroller.HostCell" }

        private var hosted: UIView?

        override func prepareForReuse() {
            super.prepareForReuse()
            hosted?.removeFromSuperview()
            hosted = nil
            transform = .identity
            alpha = 1
        }

        func host(_ view: UIView) {
            hosted?.removeFromSuperview()
            hosted = view
            view.translatesAutoresizingMaskIntoConstraints = false
            contentView.addSubview(view)
            NSLayoutConstraint.activate([
                view.leadingAnchor.constraint(equalTo: contentView.leadingAnchor),
                view.trailingAnchor.constraint(equalTo: contentView.trailingAnchor),
                view.topAnchor.constraint(equalTo: contentView.topAnchor),
                view.bottomAnchor.constraint(equalTo: contentView.bottomAnchor),
            ])
        }
    }
}

