//
//  ParallaxHeader.swift
//  Inlay — component
//
//  A stretchy, parallax image header for a scroll view. Pulling DOWN stretches
//  and zooms the image; scrolling UP parallax-shifts it slower than the content
//  and (optionally) blurs it, dims it behind a dark gradient, and fades in an
//  overlay title. Zero wiring: it observes the scroll view's contentOffset via
//  KVO and manages the contentInset for you.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `ParallaxHeader.Configuration`.
//
//      var config = ParallaxHeader.Configuration.default
//      config.height = 280
//      config.minHeight = 0          // fully scrolls away
//      config.blurOnCollapse = true
//
//      let title = UILabel()
//      title.text = "Yosemite"
//      title.font = .systemFont(ofSize: 28, weight: .bold)
//      title.textColor = .white
//      config.titleView = title       // fades in as the header collapses
//
//      let header = ParallaxHeader(image: UIImage(named: "cover"), configuration: config)
//      header.attach(to: tableView)   // any UIScrollView / UITableView / UICollectionView
//
//      // header.detach()             // when you're done (also runs on deinit)
//
//  Dependency: none
//

import UIKit

final class ParallaxHeader: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Resting height of the header.
        var height: CGFloat = 280
        /// Collapsed floor. The header never shrinks below this while scrolling
        /// up. `0` lets it scroll entirely off-screen.
        var minHeight: CGFloat = 0
        /// How much slower the image moves than the content as you scroll up,
        /// `0...1`. `0` pins the image (no parallax); `1` matches the content.
        /// Lower values feel deeper.
        var parallaxFactor: CGFloat = 0.5
        /// Stretch + zoom the image when the user pulls down past the top.
        var stretchOnPull: Bool = true
        /// Maximum extra scale applied at full stretch (e.g. `0.6` = up to 1.6x).
        var maxStretchScale: CGFloat = 0.6
        /// Cross-fade a blur over the image as it collapses.
        var blurOnCollapse: Bool = true
        /// Blur style used when `blurOnCollapse` is on.
        var blurStyle: UIBlurEffect.Style = .systemThinMaterialDark
        /// How far through the collapse (0 = resting, 1 = fully collapsed) the
        /// blur reaches full strength.
        var blurRampEnd: CGFloat = 0.85
        /// Paint a bottom-anchored dark gradient over the image for legible
        /// titles regardless of the photo.
        var overlayGradient: Bool = true
        /// Fraction of the header height the gradient occupies, `0...1`.
        var gradientHeightFraction: CGFloat = 0.55
        /// Peak opacity of the gradient's darkest stop.
        var gradientMaxAlpha: CGFloat = 0.55
        /// Content mode for the image.
        var contentMode: UIView.ContentMode = .scaleAspectFill
        /// Background shown behind the image while it stretches/zooms.
        var backgroundColor: UIColor = .secondarySystemBackground
        /// A view (typically a title) faded in as the header collapses. It is
        /// pinned to the bottom of the header, above the gradient.
        var titleView: UIView?
        /// How far through the collapse the title reaches full opacity.
        var titleFadeStart: CGFloat = 0.45
        var titleFadeEnd: CGFloat = 0.95
        /// Inset of the title view from the header's bottom + leading edges.
        var titleInset: UIEdgeInsets = .init(top: 0, left: 20, bottom: 20, right: 20)

        static let `default` = Configuration()
    }

    // MARK: - Stored properties

    private let configuration: Configuration
    private let imageView = UIImageView()
    private var blurView: UIVisualEffectView?
    private var gradientLayer: CAGradientLayer?

    private weak var scrollView: UIScrollView?
    private var observation: NSKeyValueObservation?
    /// The top inset we added, so we can restore it cleanly on detach.
    private var addedTopInset: CGFloat = 0

    // MARK: - Init

    init(image: UIImage?, configuration: Configuration = .default) {
        self.configuration = configuration
        super.init(frame: .zero)
        backgroundColor = configuration.backgroundColor
        clipsToBounds = true

        imageView.image = image
        imageView.contentMode = configuration.contentMode
        imageView.clipsToBounds = true
        addSubview(imageView)

        if configuration.blurOnCollapse {
            let blur = UIVisualEffectView(effect: UIBlurEffect(style: configuration.blurStyle))
            blur.alpha = 0
            blur.isUserInteractionEnabled = false
            addSubview(blur)
            blurView = blur
        }

        if configuration.overlayGradient {
            let gradient = CAGradientLayer()
            gradient.colors = [
                UIColor.black.withAlphaComponent(0).cgColor,
                UIColor.black.withAlphaComponent(configuration.gradientMaxAlpha).cgColor,
            ]
            gradient.startPoint = CGPoint(x: 0.5, y: 0)
            gradient.endPoint = CGPoint(x: 0.5, y: 1)
            layer.addSublayer(gradient)
            gradientLayer = gradient
        }

        if let title = configuration.titleView {
            title.alpha = 0
            addSubview(title)
        }
    }

    @available(*, unavailable)
    required init?(coder: NSCoder) { fatalError("init(coder:) is not supported") }

    deinit { detach() }

    // MARK: - Attachment

    /// Inserts the header into `scrollView`, reserves space via `contentInset`,
    /// and starts observing scroll position. Safe to call once.
    func attach(to scrollView: UIScrollView) {
        guard self.scrollView !== scrollView else { return }
        detach()
        self.scrollView = scrollView

        translatesAutoresizingMaskIntoConstraints = true
        scrollView.addSubview(self)

        // Reserve room at the top for the header.
        let inset = configuration.height
        scrollView.contentInset.top += inset
        addedTopInset = inset
        scrollView.setContentOffset(CGPoint(x: 0, y: -scrollView.adjustedContentInset.top), animated: false)

        observation = scrollView.observe(\.contentOffset, options: [.new]) { [weak self] sv, _ in
            self?.layout(for: sv)
        }
        layout(for: scrollView)
    }

    /// Stops observing and restores the inset we added. Idempotent.
    func detach() {
        observation?.invalidate()
        observation = nil
        if let sv = scrollView, addedTopInset != 0 {
            sv.contentInset.top -= addedTopInset
        }
        addedTopInset = 0
        scrollView = nil
        removeFromSuperview()
    }

    // MARK: - Scroll-driven layout

    /// Exposed so a host can drive layout manually (e.g. from
    /// `scrollViewDidScroll(_:)`) if it prefers not to rely on KVO. With
    /// `attach(to:)` this is invoked automatically.
    func scrollViewDidScroll(_ scrollView: UIScrollView) {
        layout(for: scrollView)
    }

    private func layout(for scrollView: UIScrollView) {
        let width = scrollView.bounds.width
        guard width > 0 else { return }

        let cfg = configuration
        // Distance from the natural top of the content. Negative = pulled down.
        let offsetFromTop = scrollView.contentOffset.y + scrollView.adjustedContentInset.top

        if offsetFromTop < 0, cfg.stretchOnPull {
            // ── Pulled down: anchor at top, grow downward, zoom the image. ──
            let pull = -offsetFromTop
            let stretchedHeight = cfg.height + pull
            frame = CGRect(x: 0, y: -stretchedHeight, width: width, height: stretchedHeight)

            let progress = min(pull / cfg.height, 1)
            let scale = 1 + progress * cfg.maxStretchScale
            // Grow the image view to fill, scale-zoom from its centre.
            imageView.frame = bounds
            imageView.transform = CGAffineTransform(scaleX: scale, y: scale)

            blurView?.alpha = 0
            setTitleAlpha(0)
        } else {
            // ── Resting or scrolled up: parallax-shift + collapse. ──
            let collapse = max(offsetFromTop, 0)
            // Header's on-screen height as it collapses toward minHeight.
            let visibleHeight = max(cfg.height - collapse, cfg.minHeight)

            // Parallax: the header origin moves up slower than the content.
            // At parallaxFactor 0 it stays pinned; at 1 it scrolls with content.
            let originY = -collapse * cfg.parallaxFactor
            frame = CGRect(x: 0, y: originY, width: width, height: visibleHeight)

            imageView.transform = .identity
            imageView.frame = bounds

            // Collapse progress 0…1 over the scrollable header range.
            let range = max(cfg.height - cfg.minHeight, 1)
            let progress = min(collapse / range, 1)

            if let blur = blurView {
                let denom = max(cfg.blurRampEnd, 0.0001)
                blur.frame = bounds
                blur.alpha = min(progress / denom, 1)
            }

            setTitleAlpha(titleAlpha(for: progress))
        }

        layoutOverlay()
    }

    private func titleAlpha(for progress: CGFloat) -> CGFloat {
        let start = configuration.titleFadeStart
        let end = max(configuration.titleFadeEnd, start + 0.0001)
        return min(max((progress - start) / (end - start), 0), 1)
    }

    private func setTitleAlpha(_ alpha: CGFloat) {
        configuration.titleView?.alpha = alpha
    }

    /// Re-flows the gradient layer and title view to the current bounds.
    private func layoutOverlay() {
        if let gradient = gradientLayer {
            let h = bounds.height * configuration.gradientHeightFraction
            gradient.frame = CGRect(x: 0, y: bounds.height - h, width: bounds.width, height: h)
        }
        if let title = configuration.titleView {
            let inset = configuration.titleInset
            let available = bounds.width - inset.left - inset.right
            let target = title.systemLayoutSizeFitting(
                CGSize(width: available, height: UIView.layoutFittingCompressedSize.height),
                withHorizontalFittingPriority: .required,
                verticalFittingPriority: .fittingSizeLevel)
            let size = CGSize(width: min(target.width, available), height: target.height)
            title.frame = CGRect(
                x: inset.left,
                y: bounds.height - inset.bottom - size.height,
                width: max(size.width, available),
                height: size.height)
        }
    }
}

//
//  ProgressRing.swift
//  Inlay — component
//
//  A circular, determinate progress indicator with a gradient stroke, a track
//  ring behind it, rounded line caps, a center percentage label that counts up
//  as the ring fills, an optional glow dot at the leading tip of the arc, and
//  an optional indeterminate (spinning arc) mode.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `ProgressRing.Configuration`.
//
//      var config = ProgressRing.Configuration.default
//      config.gradientStartColor = .systemTeal
//      config.gradientEndColor   = .systemIndigo
//      config.lineWidth          = 14
//      config.showsTipGlow       = true
//
//      let ring = ProgressRing(configuration: config)
//      view.addSubview(ring)
//      NSLayoutConstraint.activate([
//          ring.centerXAnchor.constraint(equalTo: view.centerXAnchor),
//          ring.centerYAnchor.constraint(equalTo: view.centerYAnchor),
//          ring.widthAnchor.constraint(equalToConstant: 160),
//          ring.heightAnchor.constraint(equalToConstant: 160),
//      ])
//      ring.setProgress(0.72, animated: true)
//
//      // Indeterminate spinner:
//      //   ring.startIndeterminate()  …  ring.stopIndeterminate()
//
//  Dependency: none
//

import UIKit

final class ProgressRing: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Thickness of the track + progress strokes.
        var lineWidth: CGFloat = 12
        /// Colour of the unfilled track ring behind the progress.
        var trackColor: UIColor = .secondarySystemFill
        /// Solid progress colour. Used when a gradient is not fully specified.
        var progressColor: UIColor = .tintColor
        /// Optional gradient start colour. When both start + end are set the
        /// stroke draws as a gradient instead of `progressColor`.
        var gradientStartColor: UIColor?
        /// Optional gradient end colour.
        var gradientEndColor: UIColor?
        /// Rounded line caps on the progress (and indeterminate) stroke.
        var roundedCaps: Bool = true
        /// Angle at which the ring begins. Default is the top (-90°).
        var startAngle: CGFloat = -.pi / 2
        /// Direction the ring fills.
        var clockwise: Bool = true
        /// Whether to show the counting-up percentage label in the centre.
        var showsPercentLabel: Bool = true
        /// Font for the percentage label.
        var percentFont: UIFont = .systemFont(ofSize: 34, weight: .bold)
        /// Colour for the percentage label.
        var percentColor: UIColor = .label
        /// Duration of the fill / count-up animation for `setProgress(_:animated:)`.
        var animationDuration: TimeInterval = 0.8
        /// Whether a soft glow dot rides the leading tip of the progress arc.
        var showsTipGlow: Bool = true

        static let `default` = Configuration()
    }

    // MARK: - Public state

    /// Current progress, 0...1.
    private(set) var progress: CGFloat = 0

    // MARK: - Private state

    private let configuration: Configuration

    private let trackLayer = CAShapeLayer()
    private let progressLayer = CAShapeLayer()
    private let gradientLayer = CAGradientLayer()
    private let tipGlowLayer = CALayer()

    private let percentLabel = UILabel()

    private var isIndeterminate = false
    private var labelLink: CADisplayLink?
    private var labelAnimationStart: CFTimeInterval = 0
    private var labelFromValue: CGFloat = 0
    private var labelToValue: CGFloat = 0
    private var labelDuration: TimeInterval = 0

    private static let spinKey = "inlay.progressRing.spin"
    private static let strokeKey = "inlay.progressRing.stroke"

    // MARK: - Init

    init(configuration: Configuration = .default) {
        self.configuration = configuration
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        super.init(coder: coder)
        setUp()
    }

    deinit {
        labelLink?.invalidate()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false
        backgroundColor = .clear

        // Track ring (background).
        trackLayer.fillColor = UIColor.clear.cgColor
        trackLayer.strokeColor = configuration.trackColor.cgColor
        trackLayer.lineWidth = configuration.lineWidth
        trackLayer.lineCap = configuration.roundedCaps ? .round : .butt
        layer.addSublayer(trackLayer)

        // Progress ring — used either as a solid stroke, or as the alpha mask
        // for the gradient layer.
        progressLayer.fillColor = UIColor.clear.cgColor
        progressLayer.strokeColor = configuration.progressColor.cgColor
        progressLayer.lineWidth = configuration.lineWidth
        progressLayer.lineCap = configuration.roundedCaps ? .round : .butt
        progressLayer.strokeStart = 0
        progressLayer.strokeEnd = 0

        if usesGradient {
            gradientLayer.startPoint = CGPoint(x: 0, y: 0)
            gradientLayer.endPoint = CGPoint(x: 1, y: 1)
            gradientLayer.colors = [
                (configuration.gradientStartColor ?? configuration.progressColor).cgColor,
                (configuration.gradientEndColor ?? configuration.progressColor).cgColor,
            ]
            gradientLayer.mask = progressLayer
            layer.addSublayer(gradientLayer)
        } else {
            layer.addSublayer(progressLayer)
        }

        // Tip glow dot.
        if configuration.showsTipGlow {
            let tip = tipColor
            tipGlowLayer.backgroundColor = tip.cgColor
            tipGlowLayer.shadowColor = tip.cgColor
            tipGlowLayer.shadowOpacity = 0.9
            tipGlowLayer.shadowRadius = 6
            tipGlowLayer.shadowOffset = .zero
            tipGlowLayer.opacity = 0
            layer.addSublayer(tipGlowLayer)
        }

        // Centre percentage label.
        if configuration.showsPercentLabel {
            percentLabel.translatesAutoresizingMaskIntoConstraints = false
            percentLabel.textAlignment = .center
            percentLabel.font = configuration.percentFont
            percentLabel.textColor = configuration.percentColor
            percentLabel.adjustsFontSizeToFitWidth = true
            percentLabel.minimumScaleFactor = 0.5
            percentLabel.text = "0%"
            addSubview(percentLabel)
            NSLayoutConstraint.activate([
                percentLabel.centerXAnchor.constraint(equalTo: centerXAnchor),
                percentLabel.centerYAnchor.constraint(equalTo: centerYAnchor),
                percentLabel.leadingAnchor.constraint(
                    greaterThanOrEqualTo: leadingAnchor, constant: 8),
                percentLabel.trailingAnchor.constraint(
                    lessThanOrEqualTo: trailingAnchor, constant: -8),
            ])
        }
    }

    private var usesGradient: Bool {
        configuration.gradientStartColor != nil && configuration.gradientEndColor != nil
    }

    private var tipColor: UIColor {
        configuration.gradientEndColor ?? configuration.progressColor
    }

    // MARK: - Public API

    /// Sets progress in 0...1 (clamped). When `animated`, the stroke fills and
    /// the centre label counts up over `configuration.animationDuration`.
    func setProgress(_ value: CGFloat, animated: Bool) {
        if isIndeterminate { stopIndeterminate() }

        let clamped = max(0, min(value, 1))
        let previous = progress
        progress = clamped

        progressLayer.removeAnimation(forKey: Self.strokeKey)

        if animated {
            let animation = CABasicAnimation(keyPath: "strokeEnd")
            animation.fromValue = previous
            animation.toValue = clamped
            animation.duration = configuration.animationDuration
            animation.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)
            progressLayer.strokeEnd = clamped
            progressLayer.add(animation, forKey: Self.strokeKey)

            animateTipGlow(from: previous, to: clamped,
                           duration: configuration.animationDuration)
            startLabelCountUp(from: previous, to: clamped,
                              duration: configuration.animationDuration)
        } else {
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            progressLayer.strokeEnd = clamped
            CATransaction.commit()
            updateTipGlowPosition(forFraction: clamped)
            tipGlowLayer.opacity = clamped > 0.001 ? 1 : 0
            setLabel(to: clamped)
        }
    }

    /// Starts a continuously rotating partial-arc spinner. The determinate
    /// progress value is preserved and restored by `stopIndeterminate()`.
    func startIndeterminate() {
        guard !isIndeterminate else { return }
        isIndeterminate = true

        labelLink?.invalidate()
        labelLink = nil

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        progressLayer.strokeStart = 0
        progressLayer.strokeEnd = 0.25
        tipGlowLayer.opacity = 0
        CATransaction.commit()

        let spin = CABasicAnimation(keyPath: "transform.rotation.z")
        spin.fromValue = 0
        spin.toValue = 2 * CGFloat.pi
        spin.duration = 1.0
        spin.repeatCount = .infinity
        spin.isRemovedOnCompletion = false
        let host: CALayer = usesGradient ? gradientLayer : progressLayer
        host.add(spin, forKey: Self.spinKey)
    }

    /// Stops the indeterminate spinner and restores the determinate progress.
    func stopIndeterminate() {
        guard isIndeterminate else { return }
        isIndeterminate = false

        let host: CALayer = usesGradient ? gradientLayer : progressLayer
        host.removeAnimation(forKey: Self.spinKey)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        progressLayer.strokeStart = 0
        progressLayer.strokeEnd = progress
        CATransaction.commit()

        updateTipGlowPosition(forFraction: progress)
        tipGlowLayer.opacity = progress > 0.001 ? 1 : 0
        setLabel(to: progress)
    }

    // MARK: - Tip glow

    private func animateTipGlow(from: CGFloat, to: CGFloat, duration: TimeInterval) {
        guard configuration.showsTipGlow else { return }
        tipGlowLayer.opacity = to > 0.001 ? 1 : 0

        let fromPoint = pointOnRing(forFraction: from)
        let toPoint = pointOnRing(forFraction: to)

        let move = CABasicAnimation(keyPath: "position")
        move.fromValue = NSValue(cgPoint: fromPoint)
        move.toValue = NSValue(cgPoint: toPoint)
        move.duration = duration
        move.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)

        CATransaction.begin()
        CATransaction.setDisableActions(true)
        tipGlowLayer.position = toPoint
        CATransaction.commit()
        tipGlowLayer.add(move, forKey: "inlay.tip.move")
    }

    private func updateTipGlowPosition(forFraction fraction: CGFloat) {
        guard configuration.showsTipGlow else { return }
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        tipGlowLayer.position = pointOnRing(forFraction: fraction)
        CATransaction.commit()
    }

    private func pointOnRing(forFraction fraction: CGFloat) -> CGPoint {
        let center = CGPoint(x: bounds.midX, y: bounds.midY)
        let radius = ringRadius
        let sweep = 2 * CGFloat.pi * fraction
        let angle = configuration.clockwise
            ? configuration.startAngle + sweep
            : configuration.startAngle - sweep
        return CGPoint(
            x: center.x + radius * cos(angle),
            y: center.y + radius * sin(angle)
        )
    }

    // MARK: - Label count-up

    private func startLabelCountUp(from: CGFloat, to: CGFloat, duration: TimeInterval) {
        guard configuration.showsPercentLabel else { return }
        labelLink?.invalidate()
        labelFromValue = from
        labelToValue = to
        labelDuration = duration
        labelAnimationStart = CACurrentMediaTime()
        let link = CADisplayLink(target: self, selector: #selector(stepLabel))
        link.add(to: .main, forMode: .common)
        labelLink = link
    }

    @objc private func stepLabel() {
        let elapsed = CACurrentMediaTime() - labelAnimationStart
        let t = labelDuration > 0 ? min(elapsed / labelDuration, 1) : 1
        // Match the stroke's ease-in-ease-out feel.
        let eased = t * t * (3 - 2 * t)
        let value = labelFromValue + (labelToValue - labelFromValue) * CGFloat(eased)
        setLabel(to: value)
        if t >= 1 {
            labelLink?.invalidate()
            labelLink = nil
            setLabel(to: labelToValue)
        }
    }

    private func setLabel(to value: CGFloat) {
        guard configuration.showsPercentLabel else { return }
        percentLabel.text = "\(Int((value * 100).rounded()))%"
    }

    // MARK: - Layout

    private var ringRadius: CGFloat {
        (min(bounds.width, bounds.height) - configuration.lineWidth) / 2
    }

    override func layoutSubviews() {
        super.layoutSubviews()

        let center = CGPoint(x: bounds.midX, y: bounds.midY)
        let radius = ringRadius
        let path = UIBezierPath(
            arcCenter: center,
            radius: radius,
            startAngle: configuration.startAngle,
            endAngle: configuration.startAngle + (configuration.clockwise ? 1 : -1) * 2 * .pi,
            clockwise: configuration.clockwise
        ).cgPath

        trackLayer.frame = bounds
        trackLayer.path = path

        progressLayer.frame = bounds
        progressLayer.path = path

        if usesGradient {
            gradientLayer.frame = bounds
        }

        // Tip glow sizing tracks the line width.
        let dot = configuration.lineWidth
        tipGlowLayer.bounds = CGRect(x: 0, y: 0, width: dot, height: dot)
        tipGlowLayer.cornerRadius = dot / 2
        if !isIndeterminate {
            updateTipGlowPosition(forFraction: progress)
            tipGlowLayer.opacity = (configuration.showsTipGlow && progress > 0.001) ? 1 : 0
        }
    }

    // MARK: - Trait changes

    override func traitCollectionDidChange(_ previousTraitCollection: UITraitCollection?) {
        super.traitCollectionDidChange(previousTraitCollection)
        guard traitCollection.hasDifferentColorAppearance(comparedTo: previousTraitCollection)
        else { return }

        // Resolve dynamic colours for the CALayers, which don't auto-update.
        trackLayer.strokeColor = configuration.trackColor.cgColor
        if !usesGradient {
            progressLayer.strokeColor = configuration.progressColor.cgColor
        } else {
            gradientLayer.colors = [
                (configuration.gradientStartColor ?? configuration.progressColor).cgColor,
                (configuration.gradientEndColor ?? configuration.progressColor).cgColor,
            ]
        }
        if configuration.showsTipGlow {
            tipGlowLayer.backgroundColor = tipColor.cgColor
            tipGlowLayer.shadowColor = tipColor.cgColor
        }
    }
}

