//
//  SettingsScreen.swift
//  Inlay — component (composite)
//
//  A drop-in, model-driven settings UI: inset-grouped cards, SF Symbol icons in
//  rounded color tiles, and the five row types you actually need — toggle,
//  disclosure, value, button, and slider. Built on top of the `vertical-list`
//  component (its scrolling + staggered entrance engine), which is itself built
//  on spring-animator. This is the reference example of a registry component
//  that depends on another registry component.
//
//      let screen = SettingsScreen(sections: [
//          .init(header: "General", rows: [
//              .toggle(icon: UIImage(systemName: "moon.fill"), iconTint: .systemIndigo,
//                      title: "Dark Mode", isOn: true) { on in print("dark:", on) },
//              .disclosure(icon: UIImage(systemName: "bell.fill"), iconTint: .systemRed,
//                          title: "Notifications", subtitle: "Sounds, badges") { print("open") },
//              .value(icon: UIImage(systemName: "globe"), iconTint: .systemBlue,
//                     title: "Language", value: "English") { print("pick language") },
//          ]),
//          .init(header: "Account", footer: "Signing out clears local data.", rows: [
//              .slider(icon: UIImage(systemName: "speaker.wave.2.fill"), iconTint: .systemPink,
//                      title: "Volume", value: 0.6, minValue: 0, maxValue: 1) { v in print(v) },
//              .button(icon: UIImage(systemName: "rectangle.portrait.and.arrow.right"),
//                      title: "Sign Out", destructive: true) { print("sign out") },
//          ]),
//      ])
//      screen.translatesAutoresizingMaskIntoConstraints = false
//      view.addSubview(screen)   // pin to edges
//
//  Dependency: vertical-list (VerticalList.swift), spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class SettingsScreen: UIView {

    // MARK: - Configuration

    struct Configuration {
        /// Tint for interactive controls (switches, sliders, default buttons).
        var accentColor: UIColor = .tintColor
        /// Minimum height of a row.
        var rowHeight: CGFloat = 52
        /// Corner radius of each grouped card.
        var groupCornerRadius: CGFloat = 12
        /// Shape of the leading icon tile.
        var iconShape: IconShape = .roundedSquare(cornerRadius: 7)
        /// Horizontal inset of the cards from the screen edges.
        var horizontalInset: CGFloat = 16
        /// Spring used by the underlying list's entrance + control feedback.
        var animation: Inlay.Spring = .lively

        enum IconShape {
            case roundedSquare(cornerRadius: CGFloat)
            case circle
        }

        static let `default` = Configuration()
    }

    // MARK: - Model

    struct Section {
        var header: String?
        var footer: String?
        var rows: [Row]

        init(header: String? = nil, footer: String? = nil, rows: [Row]) {
            self.header = header
            self.footer = footer
            self.rows = rows
        }
    }

    enum Row {
        case toggle(icon: UIImage?, iconTint: UIColor? = nil, title: String,
                    isOn: Bool, onChange: (Bool) -> Void)
        case disclosure(icon: UIImage?, iconTint: UIColor? = nil, title: String,
                        subtitle: String? = nil, onTap: () -> Void)
        case value(icon: UIImage?, iconTint: UIColor? = nil, title: String,
                   value: String, onTap: (() -> Void)? = nil)
        case button(icon: UIImage? = nil, iconTint: UIColor? = nil, title: String,
                    destructive: Bool = false, onTap: () -> Void)
        case slider(icon: UIImage?, iconTint: UIColor? = nil, title: String,
                    value: Float, minValue: Float = 0, maxValue: Float = 1,
                    onChange: (Float) -> Void)
    }

    // MARK: - Internal flattened model

    private enum Position { case top, middle, bottom, single }

    private enum Entry {
        case header(String)
        case footer(String)
        case row(Row, Position)
        case spacer(CGFloat)
    }

    // MARK: - Private

    private let configuration: Configuration
    private var sections: [Section]
    private var list: VerticalList<Entry>!

    // MARK: - Init

    init(sections: [Section], configuration: Configuration = .default) {
        self.configuration = configuration
        self.sections = sections
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        self.sections = []
        super.init(frame: .zero)
        setUp()
    }

    // MARK: - Public

    func setSections(_ sections: [Section]) {
        self.sections = sections
        list.setItems(flatten(sections))
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false
        backgroundColor = .systemGroupedBackground

        var listConfig = VerticalList<Entry>.Configuration.default
        listConfig.showsSeparators = false          // we draw our own, per-card
        listConfig.insetGroupedCards = false         // we style our own cards
        listConfig.spacing = 0
        listConfig.animation = configuration.animation
        listConfig.staggeredEntrance = true

        list = VerticalList<Entry>(
            items: flatten(sections),
            configuration: listConfig
        ) { [weak self] entry in
            self?.makeView(for: entry) ?? UIView()
        }
        list.translatesAutoresizingMaskIntoConstraints = false
        addSubview(list)
        NSLayoutConstraint.activate([
            list.topAnchor.constraint(equalTo: topAnchor),
            list.bottomAnchor.constraint(equalTo: bottomAnchor),
            list.leadingAnchor.constraint(equalTo: leadingAnchor),
            list.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])
    }

    // MARK: - Flattening

    private func flatten(_ sections: [Section]) -> [Entry] {
        var entries: [Entry] = []
        for (i, section) in sections.enumerated() {
            if i == 0 { entries.append(.spacer(12)) }
            if let header = section.header { entries.append(.header(header)) }
            for (j, row) in section.rows.enumerated() {
                let position: Position
                if section.rows.count == 1 { position = .single }
                else if j == 0 { position = .top }
                else if j == section.rows.count - 1 { position = .bottom }
                else { position = .middle }
                entries.append(.row(row, position))
            }
            if let footer = section.footer { entries.append(.footer(footer)) }
            entries.append(.spacer(section.footer == nil ? 22 : 8))
        }
        return entries
    }

    // MARK: - View building

    private func makeView(for entry: Entry) -> UIView {
        switch entry {
        case .spacer(let height):
            let v = UIView()
            v.backgroundColor = .clear
            v.heightAnchor.constraint(equalToConstant: height).isActive = true
            return v
        case .header(let text):
            return makeSectionLabel(text.uppercased(), color: .secondaryLabel, top: 4, bottom: 6)
        case .footer(let text):
            return makeSectionLabel(text, color: .secondaryLabel, top: 6, bottom: 4)
        case .row(let row, let position):
            return RowView(row: row, position: position, configuration: configuration)
        }
    }

    private func makeSectionLabel(_ text: String, color: UIColor,
                                  top: CGFloat, bottom: CGFloat) -> UIView {
        let container = UIView()
        let label = UILabel()
        label.text = text
        label.font = .preferredFont(forTextStyle: .footnote)
        label.adjustsFontForContentSizeCategory = true
        label.textColor = color
        label.numberOfLines = 0
        label.translatesAutoresizingMaskIntoConstraints = false
        container.addSubview(label)
        let inset = configuration.horizontalInset + 4
        NSLayoutConstraint.activate([
            label.topAnchor.constraint(equalTo: container.topAnchor, constant: top),
            label.bottomAnchor.constraint(equalTo: container.bottomAnchor, constant: -bottom),
            label.leadingAnchor.constraint(equalTo: container.leadingAnchor, constant: inset),
            label.trailingAnchor.constraint(equalTo: container.trailingAnchor, constant: -inset),
        ])
        return container
    }

    // MARK: - Row view

    private final class RowView: UIView {

        private let row: Row
        private let position: Position
        private let configuration: Configuration
        private let card = UIView()
        private let separator = UIView()

        init(row: Row, position: Position, configuration: Configuration) {
            self.row = row
            self.position = position
            self.configuration = configuration
            super.init(frame: .zero)
            build()
        }

        required init?(coder: NSCoder) { fatalError("init(coder:) is not supported.") }

        private func build() {
            backgroundColor = .clear

            card.backgroundColor = .secondarySystemGroupedBackground
            card.layer.cornerCurve = .continuous
            card.layer.cornerRadius = configuration.groupCornerRadius
            card.layer.maskedCorners = maskedCorners(for: position)
            card.translatesAutoresizingMaskIntoConstraints = false
            addSubview(card)

            let inset = configuration.horizontalInset
            NSLayoutConstraint.activate([
                card.topAnchor.constraint(equalTo: topAnchor),
                card.bottomAnchor.constraint(equalTo: bottomAnchor),
                card.leadingAnchor.constraint(equalTo: leadingAnchor, constant: inset),
                card.trailingAnchor.constraint(equalTo: trailingAnchor, constant: -inset),
            ])

            // Leading icon tile (optional).
            let content = UIStackView()
            content.axis = .horizontal
            content.alignment = .center
            content.spacing = 12
            content.translatesAutoresizingMaskIntoConstraints = false
            card.addSubview(content)
            NSLayoutConstraint.activate([
                content.topAnchor.constraint(equalTo: card.topAnchor, constant: 8),
                content.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -8),
                content.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 14),
                content.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -14),
                card.heightAnchor.constraint(greaterThanOrEqualToConstant: configuration.rowHeight),
            ])

            if let icon = icon(for: row) {
                content.addArrangedSubview(makeIconTile(icon, tint: iconTint(for: row)))
            }

            // Title (+ subtitle) column.
            let titleStack = UIStackView()
            titleStack.axis = .vertical
            titleStack.spacing = 1
            let titleLabel = UILabel()
            titleLabel.text = title(for: row)
            titleLabel.font = .preferredFont(forTextStyle: .body)
            titleLabel.adjustsFontForContentSizeCategory = true
            titleLabel.textColor = titleColor(for: row)
            titleStack.addArrangedSubview(titleLabel)
            if case let .disclosure(_, _, _, subtitle, _) = row, let subtitle {
                let sub = UILabel()
                sub.text = subtitle
                sub.font = .preferredFont(forTextStyle: .footnote)
                sub.adjustsFontForContentSizeCategory = true
                sub.textColor = .secondaryLabel
                titleStack.addArrangedSubview(sub)
            }
            content.addArrangedSubview(titleStack)
            content.addArrangedSubview(UIView())   // flexible spacer

            // Trailing accessory.
            if let accessory = makeAccessory(for: row) {
                content.addArrangedSubview(accessory)
            }

            // Hairline separator for non-last rows.
            if position == .top || position == .middle {
                separator.backgroundColor = .separator
                separator.translatesAutoresizingMaskIntoConstraints = false
                card.addSubview(separator)
                let leading: CGFloat = icon(for: row) == nil ? 14 : 14 + 28 + 12
                NSLayoutConstraint.activate([
                    separator.heightAnchor.constraint(equalToConstant: 1.0 / UIScreen.main.scale),
                    separator.bottomAnchor.constraint(equalTo: card.bottomAnchor),
                    separator.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: leading),
                    separator.trailingAnchor.constraint(equalTo: card.trailingAnchor),
                ])
            }

            // Whole-row tap for disclosure / value / button rows.
            switch row {
            case .disclosure, .value, .button:
                let tap = UITapGestureRecognizer(target: self, action: #selector(rowTapped))
                card.addGestureRecognizer(tap)
            case .toggle, .slider:
                break
            }
        }

        // MARK: Accessory builders

        private func makeAccessory(for row: Row) -> UIView? {
            switch row {
            case let .toggle(_, _, _, isOn, _):
                let toggle = UISwitch()
                toggle.isOn = isOn
                toggle.onTintColor = configuration.accentColor
                toggle.addTarget(self, action: #selector(switchChanged(_:)), for: .valueChanged)
                return toggle
            case .disclosure:
                return makeChevron()
            case let .value(_, _, _, value, onTap):
                let stack = UIStackView()
                stack.axis = .horizontal
                stack.alignment = .center
                stack.spacing = 6
                let valueLabel = UILabel()
                valueLabel.text = value
                valueLabel.font = .preferredFont(forTextStyle: .body)
                valueLabel.textColor = .secondaryLabel
                stack.addArrangedSubview(valueLabel)
                if onTap != nil { stack.addArrangedSubview(makeChevron()) }
                return stack
            case .button:
                return nil
            case let .slider(_, _, _, value, minValue, maxValue, _):
                let slider = UISlider()
                slider.minimumValue = minValue
                slider.maximumValue = maxValue
                slider.value = value
                slider.minimumTrackTintColor = configuration.accentColor
                slider.addTarget(self, action: #selector(sliderChanged(_:)), for: .valueChanged)
                slider.setContentHuggingPriority(.defaultLow, for: .horizontal)
                slider.widthAnchor.constraint(greaterThanOrEqualToConstant: 120).isActive = true
                return slider
            }
        }

        private func makeChevron() -> UIImageView {
            let chevron = UIImageView(image: UIImage(systemName: "chevron.right"))
            chevron.tintColor = .tertiaryLabel
            chevron.contentMode = .scaleAspectFit
            chevron.preferredSymbolConfiguration = .init(font: .preferredFont(forTextStyle: .footnote),
                                                         scale: .small)
            return chevron
        }

        private func makeIconTile(_ image: UIImage, tint: UIColor) -> UIView {
            let tile = UIView()
            tile.backgroundColor = tint
            tile.layer.cornerCurve = .continuous
            tile.translatesAutoresizingMaskIntoConstraints = false
            let side: CGFloat = 28
            switch configuration.iconShape {
            case .roundedSquare(let r): tile.layer.cornerRadius = r
            case .circle: tile.layer.cornerRadius = side / 2
            }
            let imageView = UIImageView(image: image.withRenderingMode(.alwaysTemplate))
            imageView.tintColor = .white
            imageView.contentMode = .scaleAspectFit
            imageView.preferredSymbolConfiguration = .init(pointSize: 15, weight: .semibold)
            imageView.translatesAutoresizingMaskIntoConstraints = false
            tile.addSubview(imageView)
            NSLayoutConstraint.activate([
                tile.widthAnchor.constraint(equalToConstant: side),
                tile.heightAnchor.constraint(equalToConstant: side),
                imageView.centerXAnchor.constraint(equalTo: tile.centerXAnchor),
                imageView.centerYAnchor.constraint(equalTo: tile.centerYAnchor),
            ])
            return tile
        }

        // MARK: Actions

        @objc private func rowTapped() {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
            Inlay.SpringAnimator.animate(configuration.animation) {
                self.card.backgroundColor = .tertiarySystemGroupedBackground
            } completion: {
                Inlay.SpringAnimator.animate(self.configuration.animation) {
                    self.card.backgroundColor = .secondarySystemGroupedBackground
                }
            }
            switch row {
            case let .disclosure(_, _, _, _, onTap): onTap()
            case let .value(_, _, _, _, onTap): onTap?()
            case let .button(_, _, _, _, onTap): onTap()
            default: break
            }
        }

        @objc private func switchChanged(_ sender: UISwitch) {
            if case let .toggle(_, _, _, _, onChange) = row { onChange(sender.isOn) }
        }

        @objc private func sliderChanged(_ sender: UISlider) {
            if case let .slider(_, _, _, _, _, _, onChange) = row { onChange(sender.value) }
        }

        // MARK: Row introspection

        private func icon(for row: Row) -> UIImage? {
            switch row {
            case let .toggle(icon, _, _, _, _): return icon
            case let .disclosure(icon, _, _, _, _): return icon
            case let .value(icon, _, _, _, _): return icon
            case let .button(icon, _, _, _, _): return icon
            case let .slider(icon, _, _, _, _, _, _): return icon
            }
        }

        private func iconTint(for row: Row) -> UIColor {
            let explicit: UIColor?
            switch row {
            case let .toggle(_, t, _, _, _): explicit = t
            case let .disclosure(_, t, _, _, _): explicit = t
            case let .value(_, t, _, _, _): explicit = t
            case let .button(_, t, _, _, _): explicit = t
            case let .slider(_, t, _, _, _, _, _): explicit = t
            }
            return explicit ?? configuration.accentColor
        }

        private func title(for row: Row) -> String {
            switch row {
            case let .toggle(_, _, title, _, _): return title
            case let .disclosure(_, _, title, _, _): return title
            case let .value(_, _, title, _, _): return title
            case let .button(_, _, title, _, _): return title
            case let .slider(_, _, title, _, _, _, _): return title
            }
        }

        private func titleColor(for row: Row) -> UIColor {
            if case let .button(_, _, _, destructive, _) = row {
                return destructive ? .systemRed : configuration.accentColor
            }
            return .label
        }

        private func maskedCorners(for position: Position) -> CACornerMask {
            switch position {
            case .single:
                return [.layerMinXMinYCorner, .layerMaxXMinYCorner,
                        .layerMinXMaxYCorner, .layerMaxXMaxYCorner]
            case .top:
                return [.layerMinXMinYCorner, .layerMaxXMinYCorner]
            case .bottom:
                return [.layerMinXMaxYCorner, .layerMaxXMaxYCorner]
            case .middle:
                return []
            }
        }
    }
}

//
//  SideDrawer.swift
//  Inlay — component
//
//  A slide-in side drawer (hamburger menu). A content panel springs in from the
//  leading or trailing edge while a tappable dim backdrop fades in behind it.
//  Supports an optional parallax effect (the backdrop shifts/scales as the panel
//  opens) and an interactive edge-pan gesture that drags the drawer open/closed
//  and snaps on release. Light haptic on open and close.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `SideDrawer.Configuration`.
//
//      let menu = UIView()                    // your menu content
//      menu.backgroundColor = .secondarySystemBackground
//
//      let drawer = SideDrawer(contentView: menu)
//      drawer.onOpen  = { print("opened")  }
//      drawer.onClose = { print("closed") }
//      drawer.present(in: view)               // installs + enables edge-pan
//
//      // later, e.g. from a bar-button:
//      drawer.toggle()
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class SideDrawer: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Which screen edge the panel slides in from.
        var edge: Edge = .leading
        /// How the panel's width is derived.
        var width: Width = .fraction(0.8)
        /// Color of the dim backdrop behind the panel.
        var backdropColor: UIColor = .black
        /// Maximum opacity the backdrop reaches when fully open.
        var backdropMaxAlpha: CGFloat = 0.45
        /// Rounded corner on the panel's inner (screen-facing) edge only.
        var cornerRadius: CGFloat = 24
        /// Fill color of the panel itself.
        var panelBackgroundColor: UIColor = .systemBackground
        /// How far (in points) the backdrop/content shifts for parallax.
        /// `0` disables parallax.
        var parallaxAmount: CGFloat = 28
        /// Tapping the backdrop dismisses the drawer.
        var dismissOnBackdropTap: Bool = true
        /// A screen-edge pan can drag the drawer open.
        var enableEdgePanToOpen: Bool = true
        /// Spring used for open/close/snap animations. (Shared design token.)
        var animation: Inlay.Spring = .snappy
        /// Light haptic on open and close.
        var hapticsEnabled: Bool = true

        /// The edge the drawer attaches to.
        enum Edge {
            case leading
            case trailing
        }

        /// How the panel width is computed.
        enum Width {
            /// Fraction of the host view's width (e.g. `0.8`).
            case fraction(CGFloat)
            /// A fixed point width.
            case fixed(CGFloat)
        }

        static let `default` = Configuration()
    }

    // MARK: - Public API

    /// Fires after the open animation begins.
    var onOpen: (() -> Void)?
    /// Fires after the close animation begins.
    var onClose: (() -> Void)?

    /// `true` while the drawer is open (or animating toward open).
    private(set) var isOpen: Bool = false

    // MARK: - Private state

    private let configuration: Configuration
    private let contentView: UIView

    private let backdrop = UIView()
    private let panel = UIView()           // outer: carries the shadow, no clip
    private let panelClip = UIView()       // inner: clips corner radius + fill

    /// Leading-or-trailing constraint constant we animate to drive the panel.
    private var driveConstraint: NSLayoutConstraint?
    private var panelWidth: CGFloat = 0

    private weak var host: UIView?
    private var edgePan: UIScreenEdgePanGestureRecognizer?
    private var panelPan: UIPanGestureRecognizer?

    // MARK: - Init

    init(contentView: UIView, configuration: Configuration = .default) {
        self.contentView = contentView
        self.configuration = configuration
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.contentView = UIView()
        self.configuration = .default
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false
        isUserInteractionEnabled = true

        setUpBackdrop()
        setUpPanel()
    }

    private func setUpBackdrop() {
        backdrop.translatesAutoresizingMaskIntoConstraints = false
        backdrop.backgroundColor = configuration.backdropColor
        backdrop.alpha = 0
        addSubview(backdrop)
        NSLayoutConstraint.activate([
            backdrop.topAnchor.constraint(equalTo: topAnchor),
            backdrop.bottomAnchor.constraint(equalTo: bottomAnchor),
            backdrop.leadingAnchor.constraint(equalTo: leadingAnchor),
            backdrop.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])

        if configuration.dismissOnBackdropTap {
            let tap = UITapGestureRecognizer(target: self, action: #selector(handleBackdropTap))
            backdrop.addGestureRecognizer(tap)
        }
    }

    private func setUpPanel() {
        // Outer panel carries the shadow and must NOT clip.
        panel.translatesAutoresizingMaskIntoConstraints = false
        panel.layer.shadowColor = UIColor.black.cgColor
        panel.layer.shadowOpacity = 0.25
        panel.layer.shadowRadius = 24
        panel.layer.shadowOffset = shadowOffset(for: configuration.edge)
        addSubview(panel)

        // Inner clip view rounds the screen-facing corner and fills the panel.
        panelClip.translatesAutoresizingMaskIntoConstraints = false
        panelClip.backgroundColor = configuration.panelBackgroundColor
        panelClip.layer.cornerRadius = configuration.cornerRadius
        panelClip.layer.cornerCurve = .continuous
        panelClip.layer.maskedCorners = maskedCorners(for: configuration.edge)
        panelClip.clipsToBounds = true
        panel.addSubview(panelClip)
        NSLayoutConstraint.activate([
            panelClip.topAnchor.constraint(equalTo: panel.topAnchor),
            panelClip.bottomAnchor.constraint(equalTo: panel.bottomAnchor),
            panelClip.leadingAnchor.constraint(equalTo: panel.leadingAnchor),
            panelClip.trailingAnchor.constraint(equalTo: panel.trailingAnchor),
        ])

        contentView.translatesAutoresizingMaskIntoConstraints = false
        panelClip.addSubview(contentView)
        NSLayoutConstraint.activate([
            contentView.topAnchor.constraint(equalTo: panelClip.topAnchor),
            contentView.bottomAnchor.constraint(equalTo: panelClip.bottomAnchor),
            contentView.leadingAnchor.constraint(equalTo: panelClip.leadingAnchor),
            contentView.trailingAnchor.constraint(equalTo: panelClip.trailingAnchor),
        ])

        // Panel is pinned top/bottom; its width is fixed, and a leading or
        // trailing constraint constant drives it on/off screen.
        NSLayoutConstraint.activate([
            panel.topAnchor.constraint(equalTo: topAnchor),
            panel.bottomAnchor.constraint(equalTo: bottomAnchor),
        ])

        // A pan on the panel can drag it closed (and back open while dragging).
        let pan = UIPanGestureRecognizer(target: self, action: #selector(handlePanelPan(_:)))
        panel.addGestureRecognizer(pan)
        panelPan = pan
    }

    // MARK: - Presentation

    /// Installs the drawer (closed) into `parent`, pinned to its bounds, and
    /// wires up the edge-pan-to-open gesture if enabled.
    func present(in parent: UIView, animated: Bool = true) {
        guard host == nil else { return }
        host = parent

        translatesAutoresizingMaskIntoConstraints = false
        parent.addSubview(self)
        NSLayoutConstraint.activate([
            topAnchor.constraint(equalTo: parent.topAnchor),
            bottomAnchor.constraint(equalTo: parent.bottomAnchor),
            leadingAnchor.constraint(equalTo: parent.leadingAnchor),
            trailingAnchor.constraint(equalTo: parent.trailingAnchor),
        ])

        installPanelWidthConstraint(in: parent)

        if configuration.enableEdgePanToOpen {
            let edge = UIScreenEdgePanGestureRecognizer(
                target: self, action: #selector(handleEdgePan(_:))
            )
            edge.edges = configuration.edge == .leading ? .left : .right
            parent.addGestureRecognizer(edge)
            edgePan = edge
        }

        // Start fully closed and let the host pass touches through until opened.
        isUserInteractionEnabled = false
        layoutIfNeeded()
        setDrivePosition(progress: 0)
    }

    private func installPanelWidthConstraint(in parent: UIView) {
        switch configuration.width {
        case .fraction(let f):
            let w = panel.widthAnchor.constraint(
                equalTo: widthAnchor, multiplier: max(0.1, min(f, 1.0))
            )
            w.isActive = true
        case .fixed(let points):
            panel.widthAnchor.constraint(equalToConstant: points).isActive = true
        }

        // The drive constraint pins the panel's outer edge; its constant moves
        // the panel between fully off-screen (closed) and flush (open).
        let drive: NSLayoutConstraint
        switch configuration.edge {
        case .leading:
            drive = panel.leadingAnchor.constraint(equalTo: leadingAnchor)
        case .trailing:
            drive = panel.trailingAnchor.constraint(equalTo: trailingAnchor)
        }
        drive.isActive = true
        driveConstraint = drive

        parent.layoutIfNeeded()
        panelWidth = panel.bounds.width
    }

    // MARK: - Open / Close

    func toggle() {
        isOpen ? dismiss() : open()
    }

    /// Opens the drawer.
    func open(animated: Bool = true) {
        guard host != nil, !isOpen else { return }
        ensureWidthResolved()
        isOpen = true
        isUserInteractionEnabled = true
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        onOpen?()
        animateTo(progress: 1, animated: animated, completion: nil)
    }

    func dismiss(animated: Bool = true) {
        guard host != nil, isOpen else { return }
        isOpen = false
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        onClose?()
        animateTo(progress: 0, animated: animated) { [weak self] in
            // Once closed, stop intercepting touches so the host stays usable.
            if self?.isOpen == false { self?.isUserInteractionEnabled = false }
        }
    }

    private func animateTo(progress: CGFloat, animated: Bool, completion: (() -> Void)?) {
        layoutIfNeeded()
        let work = { self.setDrivePosition(progress: progress); self.layoutIfNeeded() }
        if animated {
            Inlay.SpringAnimator.animate(configuration.animation, animations: work, completion: completion)
        } else {
            work()
            completion?()
        }
    }

    /// Maps `progress` (0 closed … 1 open) onto the drive constant, backdrop
    /// alpha, and parallax transform.
    private func setDrivePosition(progress: CGFloat) {
        let p = max(0, min(progress, 1))
        let hidden = -panelWidth      // panel pushed fully off its edge

        switch configuration.edge {
        case .leading:
            driveConstraint?.constant = hidden + panelWidth * p
        case .trailing:
            driveConstraint?.constant = -hidden - panelWidth * p
        }

        backdrop.alpha = configuration.backdropMaxAlpha * p
        applyParallax(progress: p)
    }

    private func applyParallax(progress: CGFloat) {
        guard configuration.parallaxAmount > 0 else {
            backdrop.transform = .identity
            return
        }
        let shift = configuration.parallaxAmount * progress
        let dir: CGFloat = configuration.edge == .leading ? 1 : -1
        let scale = 1 - 0.02 * progress
        backdrop.transform = CGAffineTransform(translationX: shift * dir, y: 0)
            .scaledBy(x: scale, y: scale)
    }

    // MARK: - Gestures

    @objc private func handleBackdropTap() {
        dismiss()
    }

    @objc private func handleEdgePan(_ gr: UIScreenEdgePanGestureRecognizer) {
        guard let host else { return }
        ensureWidthResolved()
        let translation = gr.translation(in: host).x
        let dir: CGFloat = configuration.edge == .leading ? 1 : -1
        let progress = max(0, min((translation * dir) / max(panelWidth, 1), 1))

        switch gr.state {
        case .began:
            isUserInteractionEnabled = true
        case .changed:
            setDrivePosition(progress: progress)
        case .ended, .cancelled, .failed:
            let velocity = gr.velocity(in: host).x * dir
            finishInteractive(progress: progress, velocity: velocity)
        default:
            break
        }
    }

    @objc private func handlePanelPan(_ gr: UIPanGestureRecognizer) {
        guard let host, isOpen || gr.state == .changed else { return }
        let translation = gr.translation(in: host).x
        let dir: CGFloat = configuration.edge == .leading ? 1 : -1
        // Dragging toward the edge (negative along open direction) closes it.
        let delta = (translation * dir) / max(panelWidth, 1)
        let progress = max(0, min(1 + delta, 1))

        switch gr.state {
        case .changed:
            setDrivePosition(progress: progress)
        case .ended, .cancelled, .failed:
            let velocity = gr.velocity(in: host).x * dir
            finishInteractive(progress: progress, velocity: velocity)
        default:
            break
        }
    }

    /// Snaps to open or closed based on how far the drag traveled and its
    /// release velocity.
    private func finishInteractive(progress: CGFloat, velocity: CGFloat) {
        let shouldOpen: Bool
        if abs(velocity) > 600 {
            shouldOpen = velocity > 0
        } else {
            shouldOpen = progress > 0.5
        }

        if shouldOpen {
            let wasOpen = isOpen
            isOpen = true
            isUserInteractionEnabled = true
            if !wasOpen {
                if configuration.hapticsEnabled {
                    UIImpactFeedbackGenerator(style: .light).impactOccurred()
                }
                onOpen?()
            }
            animateTo(progress: 1, animated: true, completion: nil)
        } else {
            let wasOpen = isOpen
            isOpen = false
            if wasOpen {
                if configuration.hapticsEnabled {
                    UIImpactFeedbackGenerator(style: .light).impactOccurred()
                }
                onClose?()
            }
            animateTo(progress: 0, animated: true) { [weak self] in
                if self?.isOpen == false { self?.isUserInteractionEnabled = false }
            }
        }
    }

    // MARK: - Helpers

    /// Width is read from the laid-out panel; re-resolve lazily in case the host
    /// laid out after `present`.
    private func ensureWidthResolved() {
        if panelWidth <= 0 {
            host?.layoutIfNeeded()
            layoutIfNeeded()
            panelWidth = panel.bounds.width
            if !isOpen { setDrivePosition(progress: 0) }
        }
    }

    private func shadowOffset(for edge: Configuration.Edge) -> CGSize {
        switch edge {
        case .leading:  return CGSize(width: 6, height: 0)
        case .trailing: return CGSize(width: -6, height: 0)
        }
    }

    private func maskedCorners(for edge: Configuration.Edge) -> CACornerMask {
        switch edge {
        case .leading:
            return [.layerMaxXMinYCorner, .layerMaxXMaxYCorner]  // round trailing edge
        case .trailing:
            return [.layerMinXMinYCorner, .layerMinXMaxYCorner]  // round leading edge
        }
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        // Shadow path tracks the panel for crisp, performant shadows.
        panel.layer.shadowPath = UIBezierPath(
            roundedRect: panel.bounds,
            cornerRadius: configuration.cornerRadius
        ).cgPath
    }
}

//
//  SkeletonView.swift
//  Inlay — component
//
//  A loading-placeholder view that sweeps a soft highlight band across a base
//  color, with rounded corners. Use it to stand in for content that hasn't
//  loaded yet. The shimmer is a pure-Core-Animation gradient sweep, so it costs
//  almost nothing and keeps running smoothly off the main thread.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `SkeletonView.Configuration`.
//
//      // A single rounded placeholder.
//      let avatar = SkeletonView()                 // auto-starts on screen
//      avatar.translatesAutoresizingMaskIntoConstraints = false
//      view.addSubview(avatar)
//      NSLayoutConstraint.activate([
//          avatar.widthAnchor.constraint(equalToConstant: 56),
//          avatar.heightAnchor.constraint(equalToConstant: 56),
//      ])
//
//      // A common list-cell placeholder: avatar + two lines of text.
//      let card = SkeletonView.card()
//      view.addSubview(card)
//
//      // A paragraph of placeholder text lines.
//      let para = SkeletonView.lines(3)
//      view.addSubview(para)
//
//  Dependency: none
//

import UIKit

final class SkeletonView: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Corner radius of the placeholder block. Use a large value (or set it
        /// to half the height) to read as a circle.
        var cornerRadius: CGFloat = 8
        /// The resting fill color shown beneath the moving highlight.
        var baseColor: UIColor = .secondarySystemFill
        /// The color of the sweeping highlight band.
        var highlightColor: UIColor = .systemFill
        /// Seconds for one full sweep of the highlight across the view.
        var shimmerDuration: CFTimeInterval = 1.4
        /// Pause between sweeps, in seconds. `0` loops continuously.
        var repeatDelay: CFTimeInterval = 0.25
        /// Direction the highlight travels.
        var direction: Direction = .leftToRight
        /// Width of the highlight band as a fraction of the sweep axis
        /// (0…1). Smaller reads as a tighter, brighter streak.
        var highlightWidth: CGFloat = 0.6
        /// Softness of the band's edges (0 = hard, 1 = fully feathered).
        var highlightSoftness: CGFloat = 1.0
        /// Begin shimmering automatically once the view reaches a window.
        var autoStarts: Bool = true

        /// Travel direction of the sweeping highlight.
        enum Direction {
            case leftToRight
            case rightToLeft
            case topToBottom
            case diagonal

            /// Start/end points for the gradient, expressed in unit space.
            fileprivate var points: (start: CGPoint, end: CGPoint) {
                switch self {
                case .leftToRight: return (CGPoint(x: 0, y: 0.5), CGPoint(x: 1, y: 0.5))
                case .rightToLeft: return (CGPoint(x: 1, y: 0.5), CGPoint(x: 0, y: 0.5))
                case .topToBottom: return (CGPoint(x: 0.5, y: 0), CGPoint(x: 0.5, y: 1))
                case .diagonal:    return (CGPoint(x: 0, y: 0),   CGPoint(x: 1, y: 1))
                }
            }
        }

        /// Sensible defaults: a subtle, premium left-to-right sweep.
        static let `default` = Configuration()
    }

    // MARK: - Stored properties

    private(set) var configuration: Configuration
    private let gradientLayer = CAGradientLayer()
    private var isShimmering = false

    private static let shimmerKey = "inlay.skeleton.shimmer"

    // MARK: - Init

    init(configuration: Configuration = .default) {
        self.configuration = configuration
        super.init(frame: .zero)
        commonInit()
    }

    @available(*, unavailable)
    required init?(coder: NSCoder) {
        fatalError("init(coder:) is not supported — SkeletonView is programmatic.")
    }

    private func commonInit() {
        translatesAutoresizingMaskIntoConstraints = false
        isUserInteractionEnabled = false
        layer.cornerCurve = .continuous
        layer.masksToBounds = true
        applyAppearance()

        gradientLayer.actions = ["position": NSNull(), "bounds": NSNull(), "transform": NSNull()]
        layer.addSublayer(gradientLayer)
        configureGradient()
    }

    // MARK: - Configuration application

    /// Apply a new configuration at runtime, restarting the shimmer if needed.
    func apply(_ configuration: Configuration) {
        let wasShimmering = isShimmering
        self.configuration = configuration
        applyAppearance()
        configureGradient()
        if wasShimmering { restart() }
    }

    private func applyAppearance() {
        layer.cornerRadius = configuration.cornerRadius
        backgroundColor = configuration.baseColor
    }

    private func configureGradient() {
        let points = configuration.direction.points
        gradientLayer.startPoint = points.start
        gradientLayer.endPoint = points.end

        // The band is the highlight color flanked by the (clear) base, so the
        // base color shows through everywhere except under the moving streak.
        let clear = configuration.highlightColor.withAlphaComponent(0).cgColor
        let solid = configuration.highlightColor.cgColor
        gradientLayer.colors = [clear, solid, clear]

        // Locations describe a band centered at 0.5; width + softness shape it.
        let half = max(0.001, min(0.5, configuration.highlightWidth / 2))
        let soft = max(0, min(1, configuration.highlightSoftness)) * half
        gradientLayer.locations = [
            NSNumber(value: Double(0.5 - half)),
            NSNumber(value: Double(0.5 - half + soft)),
            NSNumber(value: Double(0.5 + half)),
        ]
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        gradientLayer.frame = bounds
        layer.cornerRadius = configuration.cornerRadius
    }

    // MARK: - Appearance changes (dark mode)

    override func traitCollectionDidChange(_ previous: UITraitCollection?) {
        super.traitCollectionDidChange(previous)
        if traitCollection.hasDifferentColorAppearance(comparedTo: previous) {
            // CGColors don't resolve dynamic colors automatically; refresh them.
            applyAppearance()
            configureGradient()
        }
    }

    // MARK: - Window lifecycle

    override func didMoveToWindow() {
        super.didMoveToWindow()
        if window != nil {
            if configuration.autoStarts { startShimmering() }
        } else {
            // Tear down animation while off-screen to save work; remember state
            // so it resumes when re-attached.
            let resume = isShimmering
            stopShimmering()
            isShimmering = resume
        }
    }

    // MARK: - Shimmer control

    /// Start the sweeping highlight animation.
    func startShimmering() {
        isShimmering = true
        guard window != nil else { return } // resumes via didMoveToWindow
        gradientLayer.removeAnimation(forKey: Self.shimmerKey)
        gradientLayer.add(makeAnimation(), forKey: Self.shimmerKey)
    }

    /// Stop the animation and rest on the base color.
    func stopShimmering() {
        isShimmering = false
        gradientLayer.removeAnimation(forKey: Self.shimmerKey)
    }

    private func restart() {
        gradientLayer.removeAnimation(forKey: Self.shimmerKey)
        gradientLayer.add(makeAnimation(), forKey: Self.shimmerKey)
    }

    /// Build the sweep animation. The band's `locations` slide from fully before
    /// the leading edge to fully past the trailing edge, so it enters and exits
    /// cleanly. A non-zero `repeatDelay` wraps it in a group so the pause counts
    /// toward each cycle.
    private func makeAnimation() -> CAAnimation {
        let sweep = CABasicAnimation(keyPath: "locations")
        let half = max(0.001, min(0.5, configuration.highlightWidth / 2))
        let soft = max(0, min(1, configuration.highlightSoftness)) * half

        sweep.fromValue = [
            NSNumber(value: Double(-2 * half)),
            NSNumber(value: Double(-2 * half + soft)),
            NSNumber(value: Double(0.0)),
        ]
        sweep.toValue = [
            NSNumber(value: Double(1.0)),
            NSNumber(value: Double(1.0 + soft)),
            NSNumber(value: Double(1.0 + 2 * half)),
        ]
        sweep.duration = configuration.shimmerDuration
        sweep.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)

        guard configuration.repeatDelay > 0 else {
            sweep.repeatCount = .infinity
            return sweep
        }

        let group = CAAnimationGroup()
        group.animations = [sweep]
        group.duration = configuration.shimmerDuration + configuration.repeatDelay
        group.repeatCount = .infinity
        return group
    }

    // MARK: - Composition builders

    /// A vertical stack of placeholder text lines. The last line is shortened
    /// to mimic a ragged paragraph end. All lines share one shimmer phase via
    /// the same duration so they read as a coherent block.
    ///
    ///     let paragraph = SkeletonView.lines(3)
    ///     view.addSubview(paragraph)
    static func lines(_ count: Int,
                      configuration: Configuration = .default,
                      lastLineFraction: CGFloat = 0.6,
                      lineHeight: CGFloat = 12,
                      spacing: CGFloat = 8) -> UIStackView {
        var lineConfig = configuration
        // Text lines read best as rounded pills.
        lineConfig.cornerRadius = min(configuration.cornerRadius, lineHeight / 2)

        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = spacing
        stack.alignment = .fill
        stack.translatesAutoresizingMaskIntoConstraints = false

        let total = max(0, count)
        for index in 0..<total {
            let isLast = index == total - 1
            let line = SkeletonView(configuration: lineConfig)
            line.heightAnchor.constraint(equalToConstant: lineHeight).isActive = true

            if isLast && total > 1 {
                // Shorten the last line using a width fraction wrapper row.
                let row = UIView()
                row.translatesAutoresizingMaskIntoConstraints = false
                row.addSubview(line)
                NSLayoutConstraint.activate([
                    line.leadingAnchor.constraint(equalTo: row.leadingAnchor),
                    line.topAnchor.constraint(equalTo: row.topAnchor),
                    line.bottomAnchor.constraint(equalTo: row.bottomAnchor),
                    line.widthAnchor.constraint(equalTo: row.widthAnchor,
                                                multiplier: max(0.05, min(1, lastLineFraction))),
                ])
                stack.addArrangedSubview(row)
            } else {
                stack.addArrangedSubview(line)
            }
        }
        return stack
    }

    /// A common list-cell placeholder: a circular avatar beside two text lines.
    ///
    ///     let cell = SkeletonView.card()
    ///     view.addSubview(cell)
    static func card(configuration: Configuration = .default) -> UIView {
        let container = UIView()
        container.translatesAutoresizingMaskIntoConstraints = false

        let avatarSize: CGFloat = 48
        var avatarConfig = configuration
        avatarConfig.cornerRadius = avatarSize / 2
        let avatar = SkeletonView(configuration: avatarConfig)
        NSLayoutConstraint.activate([
            avatar.widthAnchor.constraint(equalToConstant: avatarSize),
            avatar.heightAnchor.constraint(equalToConstant: avatarSize),
        ])

        let titleLines = lines(2,
                               configuration: configuration,
                               lastLineFraction: 0.7,
                               lineHeight: 12,
                               spacing: 10)

        let row = UIStackView(arrangedSubviews: [avatar, titleLines])
        row.axis = .horizontal
        row.spacing = 12
        row.alignment = .center
        row.translatesAutoresizingMaskIntoConstraints = false

        container.addSubview(row)
        NSLayoutConstraint.activate([
            row.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            row.trailingAnchor.constraint(equalTo: container.trailingAnchor),
            row.topAnchor.constraint(equalTo: container.topAnchor),
            row.bottomAnchor.constraint(equalTo: container.bottomAnchor),
        ])
        return container
    }
}

