import UIKit
import CoreMotion

final class TiltCard: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Maximum rotation, in degrees, at the card's edges.
        var maxTilt: CGFloat = 14
        /// Perspective distance (points). Smaller = more dramatic 3D.
        var perspective: CGFloat = 700
        /// Corner radius of the card. `cornerCurve` is always `.continuous`.
        var cornerRadius: CGFloat = 22
        /// Whether the specular sheen overlay is drawn.
        var glareEnabled: Bool = true
        /// Colour of the sheen highlight.
        var glareColor: UIColor = .white
        /// Peak opacity of the sheen (0...1).
        var glareIntensity: CGFloat = 0.35
        /// Whether the drop shadow shifts opposite the tilt for depth.
        var shadowFollowsTilt: Bool = true
        /// Drive tilt from device attitude (CoreMotion) instead of touch.
        /// Falls back gracefully when no motion hardware is available.
        var useMotion: Bool = false
        /// Spring back to flat when the touch ends.
        var springsBackOnRelease: Bool = true
        /// Slight lift (scale) while pressed.
        var scaleOnTouch: Bool = true
        /// Scale factor applied while pressed when `scaleOnTouch` is on.
        var touchScale: CGFloat = 1.03
        /// Spring used for spring-back and press feedback. (Shared token.)
        var animation: Inlay.Spring = .lively

        static let `default` = Configuration()
    }

    // MARK: - Public

    /// The view being tilted. Provided at init; pinned to the card's bounds.
    let contentView: UIView

    // MARK: - Private state

    private let configuration: Configuration
    private let container = UIView()
    private let glareLayer = CAGradientLayer()
    private let baseShadowOffset: CGSize
    private let baseShadowRadius: CGFloat
    private var motionManager: CMMotionManager?
    private var isTracking = false

    // MARK: - Init

    init(contentView: UIView, configuration: Configuration = .default) {
        self.contentView = contentView
        self.configuration = configuration
        self.baseShadowOffset = CGSize(width: 0, height: 12)
        self.baseShadowRadius = 24
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.contentView = UIView()
        self.configuration = .default
        self.baseShadowOffset = CGSize(width: 0, height: 12)
        self.baseShadowRadius = 24
        super.init(coder: coder)
        setUp()
    }

    deinit {
        motionManager?.stopDeviceMotionUpdates()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false

        // Outer view carries the shadow and must NOT clip.
        setUpShadow()

        // Inner container clips the corner radius; it is the layer we tilt.
        container.translatesAutoresizingMaskIntoConstraints = false
        container.layer.cornerRadius = configuration.cornerRadius
        container.layer.cornerCurve = .continuous
        container.clipsToBounds = true
        addSubview(container)
        NSLayoutConstraint.activate([
            container.topAnchor.constraint(equalTo: topAnchor),
            container.bottomAnchor.constraint(equalTo: bottomAnchor),
            container.leadingAnchor.constraint(equalTo: leadingAnchor),
            container.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])

        // Content fills the container.
        contentView.translatesAutoresizingMaskIntoConstraints = false
        container.addSubview(contentView)
        NSLayoutConstraint.activate([
            contentView.topAnchor.constraint(equalTo: container.topAnchor),
            contentView.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            contentView.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            contentView.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])

        setUpGlare()

        if !configuration.useMotion {
            let pan = UIPanGestureRecognizer(target: self, action: #selector(handlePan(_:)))
            pan.maximumNumberOfTouches = 1
            addGestureRecognizer(pan)
        }
    }

    private func setUpShadow() {
        layer.shadowColor = UIColor.black.cgColor
        layer.shadowOpacity = 0.28
        layer.shadowRadius = baseShadowRadius
        layer.shadowOffset = baseShadowOffset
    }

    private func setUpGlare() {
        guard configuration.glareEnabled else { return }
        // A diagonal specular band. We move it opposite the tilt by adjusting
        // start/end points, and reveal it via opacity scaled by tilt magnitude.
        glareLayer.colors = [
            configuration.glareColor.withAlphaComponent(0).cgColor,
            configuration.glareColor.withAlphaComponent(configuration.glareIntensity).cgColor,
            configuration.glareColor.withAlphaComponent(0).cgColor,
        ]
        glareLayer.locations = [0.0, 0.5, 1.0]
        glareLayer.startPoint = CGPoint(x: 0, y: 0)
        glareLayer.endPoint = CGPoint(x: 1, y: 1)
        glareLayer.opacity = 0
        // Clip the glare to the card's rounded bounds.
        glareLayer.cornerRadius = configuration.cornerRadius
        glareLayer.masksToBounds = true
        container.layer.addSublayer(glareLayer)
    }

    // MARK: - Touch tracking

    @objc private func handlePan(_ gesture: UIPanGestureRecognizer) {
        switch gesture.state {
        case .began:
            isTracking = true
            if configuration.scaleOnTouch { applyTouchScale(true) }
            apply(point: gesture.location(in: self))
        case .changed:
            apply(point: gesture.location(in: self))
        case .ended, .cancelled, .failed:
            isTracking = false
            if configuration.scaleOnTouch { applyTouchScale(false) }
            if configuration.springsBackOnRelease { springBackToFlat() }
        default:
            break
        }
    }

    override func touchesBegan(_ touches: Set<UITouch>, with event: UIEvent?) {
        super.touchesBegan(touches, with: event)
        guard !configuration.useMotion, let touch = touches.first else { return }
        isTracking = true
        if configuration.scaleOnTouch { applyTouchScale(true) }
        apply(point: touch.location(in: self))
    }

    override func touchesMoved(_ touches: Set<UITouch>, with event: UIEvent?) {
        super.touchesMoved(touches, with: event)
        guard !configuration.useMotion, isTracking, let touch = touches.first else { return }
        apply(point: touch.location(in: self))
    }

    override func touchesEnded(_ touches: Set<UITouch>, with event: UIEvent?) {
        super.touchesEnded(touches, with: event)
        endTouchTracking()
    }

    override func touchesCancelled(_ touches: Set<UITouch>, with event: UIEvent?) {
        super.touchesCancelled(touches, with: event)
        endTouchTracking()
    }

    private func endTouchTracking() {
        guard !configuration.useMotion, isTracking else { return }
        isTracking = false
        if configuration.scaleOnTouch { applyTouchScale(false) }
        if configuration.springsBackOnRelease { springBackToFlat() }
    }

    /// Maps a point in the card's coordinate space to a normalized tilt and
    /// applies it.
    private func apply(point: CGPoint) {
        guard bounds.width > 0, bounds.height > 0 else { return }
        // Normalize to -1...1 around the centre.
        let nx = (point.x / bounds.width) * 2 - 1
        let ny = (point.y / bounds.height) * 2 - 1
        applyTilt(normalizedX: clamp(nx), normalizedY: clamp(ny), animated: false)
    }

    // MARK: - Tilt math

    /// Applies a tilt for a normalized input where `x`/`y` are in -1...1.
    /// Touching the right edge (x = +1) rotates the card so its right side
    /// recedes; touching the bottom (y = +1) tips the bottom back.
    private func applyTilt(normalizedX nx: CGFloat, normalizedY ny: CGFloat, animated: Bool) {
        let maxRadians = configuration.maxTilt * .pi / 180
        // Pointer to the right → rotate about Y so the right edge goes back.
        let rotateY = nx * maxRadians
        // Pointer down → rotate about X so the bottom edge goes back.
        let rotateX = -ny * maxRadians

        var transform = CATransform3DIdentity
        transform.m34 = -1 / configuration.perspective
        transform = CATransform3DRotate(transform, rotateX, 1, 0, 0)
        transform = CATransform3DRotate(transform, rotateY, 0, 1, 0)

        let updates = {
            self.container.layer.transform = transform
            self.updateGlare(normalizedX: nx, normalizedY: ny)
            self.updateShadow(normalizedX: nx, normalizedY: ny)
        }

        if animated {
            Inlay.SpringAnimator.animate(configuration.animation, updates)
        } else {
            // Disable implicit CA animation for snappy 1:1 tracking.
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            updates()
            CATransaction.commit()
        }
    }

    /// Move the sheen opposite the tilt and scale its strength by how far the
    /// card is tipped.
    private func updateGlare(normalizedX nx: CGFloat, normalizedY ny: CGFloat) {
        guard configuration.glareEnabled else { return }
        let magnitude = min(1, hypot(nx, ny))
        glareLayer.opacity = Float(magnitude)
        // Slide the band toward the high (lit) corner — opposite the push.
        let dx = -nx * 0.5
        let dy = -ny * 0.5
        glareLayer.startPoint = CGPoint(x: 0.5 + dx - 0.5, y: 0.5 + dy - 0.5)
        glareLayer.endPoint = CGPoint(x: 0.5 + dx + 0.5, y: 0.5 + dy + 0.5)
    }

    /// Shift the drop shadow opposite the tilt so the card appears lifted.
    private func updateShadow(normalizedX nx: CGFloat, normalizedY ny: CGFloat) {
        guard configuration.shadowFollowsTilt else { return }
        let shift: CGFloat = 16
        layer.shadowOffset = CGSize(
            width: baseShadowOffset.width - nx * shift,
            height: baseShadowOffset.height - ny * shift
        )
    }

    private func springBackToFlat() {
        applyTilt(normalizedX: 0, normalizedY: 0, animated: true)
    }

    private func applyTouchScale(_ pressed: Bool) {
        guard configuration.scaleOnTouch else { return }
        let scale = pressed ? configuration.touchScale : 1
        Inlay.SpringAnimator.animate(configuration.animation) {
            self.transform = CGAffineTransform(scaleX: scale, y: scale)
        }
    }

    private func clamp(_ value: CGFloat) -> CGFloat {
        max(-1, min(1, value))
    }

    // MARK: - Motion (gyro mode)

    override func didMoveToWindow() {
        super.didMoveToWindow()
        guard configuration.useMotion else { return }
        if window != nil {
            startMotion()
        } else {
            stopMotion()
        }
    }

    private func startMotion() {
        let manager = motionManager ?? CMMotionManager()
        motionManager = manager
        guard manager.isDeviceMotionAvailable else { return }
        guard !manager.isDeviceMotionActive else { return }
        manager.deviceMotionUpdateInterval = 1.0 / 60.0
        manager.startDeviceMotionUpdates(to: .main) { [weak self] motion, _ in
            guard let self, let motion else { return }
            // Map attitude roll/pitch (radians) to normalized -1...1, clamped
            // so resting at ~30° already hits the max tilt.
            let span: CGFloat = .pi / 6
            let nx = self.clamp(CGFloat(motion.attitude.roll) / span)
            let ny = self.clamp(CGFloat(motion.attitude.pitch) / span)
            self.applyTilt(normalizedX: nx, normalizedY: ny, animated: false)
        }
    }

    private func stopMotion() {
        motionManager?.stopDeviceMotionUpdates()
    }

    // MARK: - Layout

    override func layoutSubviews() {
        super.layoutSubviews()
        // Anchor the 3D rotation about the card's centre.
        container.layer.anchorPoint = CGPoint(x: 0.5, y: 0.5)
        glareLayer.frame = container.bounds
        glareLayer.cornerRadius = configuration.cornerRadius
        // Shadow path tracks the card shape for crisp, performant shadows.
        layer.shadowPath = UIBezierPath(
            roundedRect: bounds,
            cornerRadius: configuration.cornerRadius
        ).cgPath
    }
}

//
//  Toast.swift
//  Inlay — component
//
//  A transient notification banner that springs in from the top or bottom,
//  auto-dismisses, supports swipe-to-dismiss, drains a thin progress bar over
//  its lifetime, and stacks (rather than overlaps) when several are shown.
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Present it with the static API — no need to keep a reference around.
//
//      Toast.show("Saved to your library", style: .success)
//
//      // Customised:
//      var config = Toast.Configuration.default
//      config.position = .bottom
//      config.duration = 4
//      config.background = .glass(.systemUltraThinMaterial)
//      Toast.show("Couldn't sync — tap to retry",
//                 style: .error,
//                 configuration: config,
//                 in: myView) // omit `in:` to present over the key window
//
//  Everything is customised through `Toast.Configuration`.
//
//  Dependency: spring-animator (Inlay+SpringAnimator.swift)
//

import UIKit

final class Toast: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {

        /// Semantic styles. Each picks a default SF Symbol + accent tint.
        enum Style {
            case info
            case success
            case warning
            case error

            /// Default SF Symbol shown when no explicit icon is passed.
            var symbolName: String {
                switch self {
                case .info:    return "info.circle.fill"
                case .success: return "checkmark.circle.fill"
                case .warning: return "exclamationmark.triangle.fill"
                case .error:   return "xmark.octagon.fill"
                }
            }

            /// Accent tint used for the icon and progress bar.
            var accent: UIColor {
                switch self {
                case .info:    return .systemBlue
                case .success: return .systemGreen
                case .warning: return .systemOrange
                case .error:   return .systemRed
                }
            }
        }

        /// Which edge the toast docks against and animates from.
        enum Position {
            case top
            case bottom
        }

        /// Background appearance of the toast surface.
        enum Background {
            case glass(UIBlurEffect.Style)
            case solid(UIColor)
        }

        /// Edge the toast docks against and springs in/out from.
        var position: Position = .top
        /// Seconds the toast stays on screen before auto-dismissing.
        var duration: TimeInterval = 3
        /// Corner radius of the toast surface.
        var cornerRadius: CGFloat = 18
        /// Background appearance.
        var background: Background = .glass(.systemThinMaterial)
        /// Whether the leading icon is shown.
        var showsIcon: Bool = true
        /// Whether the draining progress bar is shown.
        var showsProgressBar: Bool = true
        /// Whether a pan gesture can flick the toast away.
        var swipeToDismiss: Bool = true
        /// Haptic feedback on show (style-dependent).
        var hapticsEnabled: Bool = true
        /// Spring used for entrance, exit, and stack reflow. (Shared token.)
        var animation: Inlay.Spring = .lively
        /// Maximum width of the toast surface.
        var maxWidth: CGFloat = 460
        /// Padding from the safe-area edge and screen sides.
        var insets: UIEdgeInsets = .init(top: 12, left: 16, bottom: 12, right: 16)

        static let `default` = Configuration()
    }

    // MARK: - Static presentation API

    /// Currently on-screen toasts, newest last. Used for stacking + reflow.
    private static var active: [Toast] = []

    /// Present a toast. If `view` is nil it is added to the key window's safe
    /// area so it floats above whatever view controller is on screen.
    @discardableResult
    static func show(
        _ message: String,
        icon: UIImage? = nil,
        style: Configuration.Style = .info,
        configuration: Configuration = .default,
        in view: UIView? = nil
    ) -> Toast? {
        guard let host = view ?? Toast.hostWindow() else { return nil }

        let toast = Toast(
            message: message,
            icon: icon,
            style: style,
            configuration: configuration
        )
        host.addSubview(toast)
        toast.pin(to: host)
        active.append(toast)

        host.layoutIfNeeded()
        toast.fireHaptic()
        toast.restack(animated: false)   // place it off-screen at its slot
        toast.animateIn()
        return toast
    }

    /// Finds a sensible window to present over without a passed view.
    private static func hostWindow() -> UIWindow? {
        let scenes = UIApplication.shared.connectedScenes
            .compactMap { $0 as? UIWindowScene }
            .filter { $0.activationState == .foregroundActive }
        let scene = scenes.first ?? UIApplication.shared.connectedScenes
            .compactMap { $0 as? UIWindowScene }.first
        return scene?.keyWindow ?? scene?.windows.first { $0.isKeyWindow }
            ?? scene?.windows.first
    }

    /// Re-lays the active stack so toasts offset instead of overlapping.
    private static func relayout(animated: Bool) {
        for toast in active { toast.restack(animated: animated) }
    }

    // MARK: - Private state

    private let configuration: Configuration
    private let style: Configuration.Style
    private let message: String
    private let icon: UIImage?

    private let container = UIView()
    private var backgroundView = UIView()
    private let iconView = UIImageView()
    private let label = UILabel()
    private let progressBar = UIView()

    private var edgeConstraint: NSLayoutConstraint?
    private var progressWidth: NSLayoutConstraint?

    private var dismissTimer: Timer?
    private var progressAnimator: UIViewPropertyAnimator?
    private var isDismissing = false
    private var stackOffset: CGFloat = 0

    // MARK: - Init

    private init(
        message: String,
        icon: UIImage?,
        style: Configuration.Style,
        configuration: Configuration
    ) {
        self.message = message
        self.icon = icon
        self.style = style
        self.configuration = configuration
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        fatalError("Toast is created through Toast.show(_:)")
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false
        setUpShadow()

        // Inner container clips the corner radius + background.
        container.translatesAutoresizingMaskIntoConstraints = false
        container.layer.cornerRadius = configuration.cornerRadius
        container.layer.cornerCurve = .continuous
        container.clipsToBounds = true
        addSubview(container)
        NSLayoutConstraint.activate([
            container.topAnchor.constraint(equalTo: topAnchor),
            container.bottomAnchor.constraint(equalTo: bottomAnchor),
            container.leadingAnchor.constraint(equalTo: leadingAnchor),
            container.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])

        setUpBackground()
        setUpContent()
        setUpProgressBar()
        setUpGestures()
    }

    private func setUpShadow() {
        layer.shadowColor = UIColor.black.cgColor
        layer.shadowOpacity = 0.20
        layer.shadowRadius = 20
        layer.shadowOffset = CGSize(width: 0, height: 10)
    }

    private func setUpBackground() {
        switch configuration.background {
        case .glass(let style):
            backgroundView = UIVisualEffectView(effect: UIBlurEffect(style: style))
        case .solid(let color):
            let view = UIView()
            view.backgroundColor = color
            backgroundView = view
        }
        backgroundView.translatesAutoresizingMaskIntoConstraints = false
        backgroundView.isUserInteractionEnabled = false
        container.addSubview(backgroundView)
        NSLayoutConstraint.activate([
            backgroundView.topAnchor.constraint(equalTo: container.topAnchor),
            backgroundView.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            backgroundView.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            backgroundView.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])

        // Hairline accent border for a premium edge in both color schemes.
        container.layer.borderWidth = 1.0 / UIScreen.main.scale
        container.layer.borderColor = UIColor.separator.withAlphaComponent(0.4).cgColor
    }

    private func setUpContent() {
        let stack = UIStackView()
        stack.axis = .horizontal
        stack.alignment = .center
        stack.spacing = 12
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.isLayoutMarginsRelativeArrangement = true
        stack.layoutMargins = UIEdgeInsets(top: 14, left: 16, bottom: 14, right: 16)

        if configuration.showsIcon {
            let symbolConfig = UIImage.SymbolConfiguration(
                pointSize: 20, weight: .semibold
            )
            iconView.image = (icon ?? UIImage(
                systemName: style.symbolName,
                withConfiguration: symbolConfig
            ))?.withConfiguration(symbolConfig)
            iconView.tintColor = style.accent
            iconView.contentMode = .scaleAspectFit
            iconView.setContentHuggingPriority(.required, for: .horizontal)
            iconView.translatesAutoresizingMaskIntoConstraints = false
            iconView.widthAnchor.constraint(equalToConstant: 24).isActive = true
            iconView.heightAnchor.constraint(equalToConstant: 24).isActive = true
            stack.addArrangedSubview(iconView)
        }

        label.text = message
        label.numberOfLines = 0
        label.textColor = .label
        label.font = .preferredFont(forTextStyle: .subheadline)
        label.adjustsFontForContentSizeCategory = true
        label.setContentHuggingPriority(.defaultLow, for: .horizontal)
        stack.addArrangedSubview(label)

        container.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: container.topAnchor),
            stack.bottomAnchor.constraint(equalTo: container.bottomAnchor),
            stack.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            stack.trailingAnchor.constraint(equalTo: container.trailingAnchor),
        ])
    }

    private func setUpProgressBar() {
        guard configuration.showsProgressBar else { return }
        progressBar.backgroundColor = style.accent
        progressBar.translatesAutoresizingMaskIntoConstraints = false
        progressBar.layer.cornerRadius = 1.5
        progressBar.layer.cornerCurve = .continuous
        container.addSubview(progressBar)

        // Progress bar sits along the inner edge (away from the docked edge).
        let edgeAnchor = configuration.position == .top
            ? progressBar.bottomAnchor.constraint(equalTo: container.bottomAnchor)
            : progressBar.topAnchor.constraint(equalTo: container.topAnchor)

        let width = progressBar.widthAnchor.constraint(
            equalTo: container.widthAnchor
        )
        progressWidth = width
        NSLayoutConstraint.activate([
            edgeAnchor,
            progressBar.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            progressBar.heightAnchor.constraint(equalToConstant: 3),
            width,
        ])
    }

    private func setUpGestures() {
        let tap = UITapGestureRecognizer(target: self, action: #selector(handleTap))
        addGestureRecognizer(tap)

        if configuration.swipeToDismiss {
            let pan = UIPanGestureRecognizer(target: self, action: #selector(handlePan(_:)))
            addGestureRecognizer(pan)
        }
    }

    // MARK: - Layout

    /// Optional tap handler, run on tap before dismissing.
    var onTap: (() -> Void)?

    private func pin(to host: UIView) {
        let guide = host.safeAreaLayoutGuide
        let edge: NSLayoutConstraint
        switch configuration.position {
        case .top:
            edge = topAnchor.constraint(
                equalTo: guide.topAnchor, constant: configuration.insets.top
            )
        case .bottom:
            edge = bottomAnchor.constraint(
                equalTo: guide.bottomAnchor, constant: -configuration.insets.bottom
            )
        }
        edgeConstraint = edge

        let width = widthAnchor.constraint(lessThanOrEqualToConstant: configuration.maxWidth)
        width.priority = .required

        NSLayoutConstraint.activate([
            edge,
            centerXAnchor.constraint(equalTo: host.centerXAnchor),
            leadingAnchor.constraint(
                greaterThanOrEqualTo: guide.leadingAnchor,
                constant: configuration.insets.left
            ),
            trailingAnchor.constraint(
                lessThanOrEqualTo: guide.trailingAnchor,
                constant: -configuration.insets.right
            ),
            width,
        ])
    }

    override func layoutSubviews() {
        super.layoutSubviews()
        // Shadow path tracks the surface shape for crisp, performant shadows.
        layer.shadowPath = UIBezierPath(
            roundedRect: bounds,
            cornerRadius: configuration.cornerRadius
        ).cgPath
    }

    // MARK: - Stacking

    /// Computes this toast's offset based on toasts ahead of it on the same
    /// edge, then animates the edge constraint to that slot.
    private func restack(animated: Bool) {
        guard let edge = edgeConstraint, let index = Toast.active.firstIndex(of: self)
        else { return }

        // Sum heights of toasts in front (closer to the edge) of this one.
        var offset: CGFloat = 0
        let ahead = Toast.active[..<index].filter {
            $0.configuration.position == configuration.position && !$0.isDismissing
        }
        for toast in ahead {
            offset += toast.bounds.height + 10
        }
        stackOffset = offset

        let base: CGFloat
        switch configuration.position {
        case .top:    base = configuration.insets.top + offset
        case .bottom: base = -(configuration.insets.bottom + offset)
        }
        edge.constant = base

        guard animated else {
            superview?.layoutIfNeeded()
            return
        }
        Inlay.SpringAnimator.animate(configuration.animation) {
            self.superview?.layoutIfNeeded()
        }
    }

    // MARK: - Entrance / exit

    private func animateIn() {
        // Start off-screen on the docked edge.
        let host = superview
        host?.layoutIfNeeded()
        alpha = 0
        transform = offscreenTransform()

        Inlay.SpringAnimator.animate(configuration.animation, animations: {
            self.alpha = 1
            self.transform = .identity
        }, completion: { [weak self] in
            self?.startCountdown()
        })
    }

    private func offscreenTransform() -> CGAffineTransform {
        let distance = (bounds.height > 0 ? bounds.height : 80) + 60 + stackOffset
        switch configuration.position {
        case .top:    return CGAffineTransform(translationX: 0, y: -distance)
        case .bottom: return CGAffineTransform(translationX: 0, y: distance)
        }
    }

    private func startCountdown() {
        guard configuration.duration > 0 else { return }
        startProgressDrain()
        dismissTimer = Timer.scheduledTimer(
            withTimeInterval: configuration.duration, repeats: false
        ) { [weak self] _ in
            self?.dismiss()
        }
    }

    private func startProgressDrain() {
        guard configuration.showsProgressBar, let width = progressWidth else { return }
        layoutIfNeeded()
        let animator = UIViewPropertyAnimator(
            duration: configuration.duration, curve: .linear
        ) { [weak self] in
            width.isActive = false
            self?.progressWidth = self?.progressBar.widthAnchor.constraint(equalToConstant: 0)
            self?.progressWidth?.isActive = true
            self?.layoutIfNeeded()
        }
        animator.startAnimation()
        progressAnimator = animator
    }

    /// Dismisses the toast: slides back out the docked edge while fading.
    func dismiss() {
        guard !isDismissing else { return }
        isDismissing = true
        dismissTimer?.invalidate()
        progressAnimator?.stopAnimation(true)

        Inlay.SpringAnimator.animate(configuration.animation, animations: {
            self.alpha = 0
            self.transform = self.offscreenTransform()
        }, completion: { [weak self] in
            self?.finishRemoval()
        })
    }

    private func finishRemoval() {
        removeFromSuperview()
        Toast.active.removeAll { $0 === self }
        Toast.relayout(animated: true)
    }

    // MARK: - Interaction

    @objc private func handleTap() {
        if configuration.hapticsEnabled {
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
        onTap?()
        dismiss()
    }

    @objc private func handlePan(_ gesture: UIPanGestureRecognizer) {
        guard let host = superview else { return }
        let translation = gesture.translation(in: host)

        switch gesture.state {
        case .began, .changed:
            dismissTimer?.invalidate()
            progressAnimator?.pauseAnimation()
            // Resist dragging toward the screen, follow toward the edge.
            var dy = translation.y
            let towardEdge = configuration.position == .top ? dy < 0 : dy > 0
            if !towardEdge { dy *= 0.3 }
            transform = CGAffineTransform(translationX: 0, y: dy)
            let progress = min(abs(dy) / 120, 1)
            alpha = 1 - progress * 0.6

        case .ended, .cancelled:
            let velocity = gesture.velocity(in: host).y
            let dy = translation.y
            let flicked = configuration.position == .top
                ? (dy < -50 || velocity < -600)
                : (dy > 50 || velocity > 600)
            if flicked {
                dismiss()
            } else {
                // Snap back and resume the countdown.
                Inlay.SpringAnimator.animate(configuration.animation) {
                    self.transform = .identity
                    self.alpha = 1
                }
                progressAnimator?.startAnimation()
                if configuration.duration > 0 {
                    let remaining = configuration.duration * Double(1 - (progressAnimator?.fractionComplete ?? 0))
                    dismissTimer = Timer.scheduledTimer(
                        withTimeInterval: max(remaining, 0.8), repeats: false
                    ) { [weak self] _ in self?.dismiss() }
                }
            }

        default:
            break
        }
    }

    // MARK: - Haptics

    private func fireHaptic() {
        guard configuration.hapticsEnabled else { return }
        switch style {
        case .success:
            UINotificationFeedbackGenerator().notificationOccurred(.success)
        case .error:
            UINotificationFeedbackGenerator().notificationOccurred(.error)
        case .warning:
            UINotificationFeedbackGenerator().notificationOccurred(.warning)
        case .info:
            UIImpactFeedbackGenerator(style: .light).impactOccurred()
        }
    }
}

//
//  TypewriterLabel.swift
//  Inlay — component
//
//  A label that types itself in, character-by-character, with a blinking caret.
//  Supports a single-string mode and a looping cycle mode that types a string,
//  pauses, deletes it, and moves on to the next — the classic hero-tagline
//  effect ("Build faster." → "Ship sooner." → "Own your code.").
//
//  ── How to use ────────────────────────────────────────────────────────────
//  Paste this file into your project. It runs as-is, no setup required.
//  Everything is customized through `TypewriterLabel.Configuration`.
//
//      // Single string:
//      let label = TypewriterLabel()
//      view.addSubview(label)
//      label.translatesAutoresizingMaskIntoConstraints = false
//      NSLayoutConstraint.activate([
//          label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
//          label.centerYAnchor.constraint(equalTo: view.centerYAnchor),
//      ])
//      label.onFinish = { print("done typing") }
//      label.type("Hello, world.")
//
//      // Cycling hero tagline:
//      var config = TypewriterLabel.Configuration.default
//      config.font = .systemFont(ofSize: 32, weight: .bold)
//      config.loops = true
//      let hero = TypewriterLabel(configuration: config)
//      hero.cycle(["Build faster.", "Ship sooner.", "Own your code."])
//
//  Dependency: none
//

import UIKit

final class TypewriterLabel: UIView {

    // MARK: - Configuration

    /// All visual + behavioural knobs. Nested so it can never collide with
    /// another component's `Configuration`.
    struct Configuration {
        /// Font for the typed text.
        var font: UIFont = .systemFont(ofSize: 24, weight: .semibold)
        /// Color of the typed text.
        var textColor: UIColor = .label
        /// Typing speed, in characters per second.
        var typingSpeed: Double = 18
        /// Deleting speed, in characters per second (cycle mode).
        var deletingSpeed: Double = 30
        /// Pause (seconds) once a string is fully typed, before deleting.
        var pauseAfterTyping: TimeInterval = 1.4
        /// Pause (seconds) once a string is fully deleted, before the next.
        var pauseAfterDeleting: TimeInterval = 0.3
        /// Whether cycling loops back to the first string after the last.
        var loops: Bool = true
        /// Whether the blinking caret is shown.
        var showsCaret: Bool = true
        /// Color of the caret. Falls back to `textColor` when nil.
        var caretColor: UIColor? = nil
        /// Width of the caret, in points.
        var caretWidth: CGFloat = 2
        /// Caret blink period, in seconds (one fade in/out cycle).
        var caretBlinkRate: TimeInterval = 0.5
        /// Start automatically the first time the view enters a window.
        var startsOnAppear: Bool = true
        /// Text alignment of the underlying label.
        var textAlignment: NSTextAlignment = .natural
        /// Number of lines (0 = unlimited).
        var numberOfLines: Int = 1

        static let `default` = Configuration()
    }

    // MARK: - Public API

    let configuration: Configuration

    /// Called when a single-string `type(_:)` finishes. Not called in cycle mode.
    var onFinish: (() -> Void)?

    /// `true` while typing or deleting is actively in progress.
    private(set) var isRunning = false

    // MARK: - Private state

    private enum Mode {
        case idle
        case single(String)
        case cycle([String])
    }

    private enum Phase {
        case typing
        case pausingAfterTyping
        case deleting
        case pausingAfterDeleting
    }

    private let label = UILabel()
    private let caret = UIView()

    private var caretWidthConstraint: NSLayoutConstraint!
    private var caretHeightConstraint: NSLayoutConstraint!

    private var mode: Mode = .idle
    private var phase: Phase = .typing
    private var cycleIndex = 0
    private var charIndex = 0
    private var current = ""
    private var hasAutoStarted = false
    private var pendingAutoStart: Mode? = nil

    private var tickTimer: Timer?
    private var pauseTimer: Timer?

    // MARK: - Init

    init(configuration: Configuration = .default) {
        self.configuration = configuration
        super.init(frame: .zero)
        setUp()
    }

    required init?(coder: NSCoder) {
        self.configuration = .default
        super.init(coder: coder)
        setUp()
    }

    // MARK: - Setup

    private func setUp() {
        translatesAutoresizingMaskIntoConstraints = false

        label.translatesAutoresizingMaskIntoConstraints = false
        label.font = configuration.font
        label.textColor = configuration.textColor
        label.textAlignment = configuration.textAlignment
        label.numberOfLines = configuration.numberOfLines
        label.text = ""
        addSubview(label)

        caret.translatesAutoresizingMaskIntoConstraints = false
        caret.backgroundColor = configuration.caretColor ?? configuration.textColor
        caret.layer.cornerRadius = configuration.caretWidth / 2
        caret.layer.cornerCurve = .continuous
        caret.isHidden = !configuration.showsCaret
        addSubview(caret)

        caretWidthConstraint = caret.widthAnchor.constraint(
            equalToConstant: configuration.caretWidth)
        caretHeightConstraint = caret.heightAnchor.constraint(
            equalToConstant: caretHeight())

        NSLayoutConstraint.activate([
            label.topAnchor.constraint(equalTo: topAnchor),
            label.leadingAnchor.constraint(equalTo: leadingAnchor),
            label.bottomAnchor.constraint(equalTo: bottomAnchor),

            // The caret hugs the trailing edge of the label's intrinsic content,
            // so it always sits right after the last typed character.
            caret.leadingAnchor.constraint(equalTo: label.trailingAnchor, constant: 2),
            caret.trailingAnchor.constraint(equalTo: trailingAnchor),
            caret.centerYAnchor.constraint(equalTo: label.centerYAnchor),
            caretWidthConstraint,
            caretHeightConstraint,
        ])

        // Keep the label tight so the caret tracks the text edge.
        label.setContentHuggingPriority(.required, for: .horizontal)
        label.setContentCompressionResistancePriority(.required, for: .horizontal)
    }

    private func caretHeight() -> CGFloat {
        // A caret a touch shorter than the line height reads as premium.
        max(configuration.font.lineHeight * 0.9, configuration.font.pointSize)
    }

    // MARK: - Public control

    /// Type a single string in. Calls `onFinish` when complete. Cancels any
    /// in-flight animation.
    func type(_ text: String) {
        start(mode: .single(text))
    }

    /// Cycle through several strings: type, pause, delete, repeat. Loops when
    /// `configuration.loops` is true. Cancels any in-flight animation.
    func cycle(_ texts: [String]) {
        let nonEmpty = texts.filter { !$0.isEmpty }
        guard !nonEmpty.isEmpty else { return }
        start(mode: .cycle(nonEmpty))
    }

    /// Pause the animation in place (timers stop; state is preserved).
    func pause() {
        guard isRunning else { return }
        isRunning = false
        invalidateTimers()
    }

    /// Resume after `pause()`.
    func resume() {
        guard !isRunning, !isIdle else { return }
        isRunning = true
        scheduleNext()
    }

    /// Stop and clear all state and displayed text.
    func reset() {
        invalidateTimers()
        isRunning = false
        mode = .idle
        phase = .typing
        cycleIndex = 0
        charIndex = 0
        current = ""
        label.text = ""
        startCaretBlink()
    }

    // MARK: - Driver

    private var isIdle: Bool {
        if case .idle = mode { return true }
        return false
    }

    private func start(mode newMode: Mode) {
        // Defer until we're in a window if startsOnAppear is set and we haven't
        // appeared yet — mirrors how the FloatingToolbar defers its entrance.
        if configuration.startsOnAppear, window == nil, !hasAutoStarted {
            pendingAutoStart = newMode
            // Still prime the displayed string so layout is stable pre-appear.
            primeState(for: newMode)
            return
        }
        pendingAutoStart = nil
        primeState(for: newMode)
        isRunning = true
        startCaretBlink()
        scheduleNext()
    }

    private func primeState(for newMode: Mode) {
        invalidateTimers()
        mode = newMode
        phase = .typing
        cycleIndex = 0
        charIndex = 0
        current = displayString(for: newMode, at: 0) ?? ""
        label.text = ""
    }

    private func displayString(for mode: Mode, at index: Int) -> String? {
        switch mode {
        case .idle: return nil
        case .single(let s): return s
        case .cycle(let arr):
            guard arr.indices.contains(index) else { return nil }
            return arr[index]
        }
    }

    private func scheduleNext() {
        guard isRunning else { return }
        switch phase {
        case .typing:
            scheduleTick(interval: 1.0 / max(configuration.typingSpeed, 0.01),
                         action: { [weak self] in self?.typeStep() })
        case .deleting:
            scheduleTick(interval: 1.0 / max(configuration.deletingSpeed, 0.01),
                         action: { [weak self] in self?.deleteStep() })
        case .pausingAfterTyping:
            schedulePause(after: configuration.pauseAfterTyping) { [weak self] in
                self?.phase = .deleting
                self?.scheduleNext()
            }
        case .pausingAfterDeleting:
            schedulePause(after: configuration.pauseAfterDeleting) { [weak self] in
                self?.advanceToNextString()
            }
        }
    }

    private func typeStep() {
        let chars = Array(current)
        guard charIndex < chars.count else {
            finishedTyping()
            return
        }
        charIndex += 1
        label.text = String(chars[0..<charIndex])
        if charIndex >= chars.count {
            finishedTyping()
        } else {
            scheduleNext()
        }
    }

    private func deleteStep() {
        guard charIndex > 0 else {
            finishedDeleting()
            return
        }
        charIndex -= 1
        let chars = Array(current)
        label.text = String(chars[0..<charIndex])
        if charIndex == 0 {
            finishedDeleting()
        } else {
            scheduleNext()
        }
    }

    private func finishedTyping() {
        switch mode {
        case .single:
            isRunning = false
            invalidateTimers()
            onFinish?()
        case .cycle:
            phase = .pausingAfterTyping
            scheduleNext()
        case .idle:
            isRunning = false
        }
    }

    private func finishedDeleting() {
        phase = .pausingAfterDeleting
        scheduleNext()
    }

    private func advanceToNextString() {
        guard case .cycle(let arr) = mode else { return }
        var next = cycleIndex + 1
        if next >= arr.count {
            if configuration.loops {
                next = 0
            } else {
                isRunning = false
                invalidateTimers()
                return
            }
        }
        cycleIndex = next
        current = arr[next]
        charIndex = 0
        phase = .typing
        label.text = ""
        scheduleNext()
    }

    // MARK: - Timers

    private func scheduleTick(interval: TimeInterval, action: @escaping () -> Void) {
        tickTimer?.invalidate()
        let timer = Timer(timeInterval: interval, repeats: false) { _ in action() }
        RunLoop.main.add(timer, forMode: .common)
        tickTimer = timer
    }

    private func schedulePause(after delay: TimeInterval,
                               action: @escaping () -> Void) {
        pauseTimer?.invalidate()
        let timer = Timer(timeInterval: max(delay, 0), repeats: false) { _ in action() }
        RunLoop.main.add(timer, forMode: .common)
        pauseTimer = timer
    }

    private func invalidateTimers() {
        tickTimer?.invalidate()
        tickTimer = nil
        pauseTimer?.invalidate()
        pauseTimer = nil
    }

    // MARK: - Caret blink

    private func startCaretBlink() {
        guard configuration.showsCaret else {
            caret.isHidden = true
            return
        }
        caret.isHidden = false
        caret.layer.removeAllAnimations()
        caret.alpha = 1
        UIView.animate(
            withDuration: max(configuration.caretBlinkRate, 0.05),
            delay: 0,
            options: [.repeat, .autoreverse, .curveEaseInOut, .allowUserInteraction],
            animations: { [weak self] in self?.caret.alpha = 0 },
            completion: nil)
    }

    private func stopCaretBlink() {
        caret.layer.removeAllAnimations()
        caret.alpha = 1
    }

    // MARK: - Lifecycle

    override func didMoveToWindow() {
        super.didMoveToWindow()
        if window != nil {
            startCaretBlink()
            if configuration.startsOnAppear, !hasAutoStarted,
               let pending = pendingAutoStart {
                hasAutoStarted = true
                start(mode: pending)
            } else if isRunning {
                // Returning to a window — keep going.
                scheduleNext()
            }
        } else {
            // Removed from window: cancel all timers, stop the blink.
            invalidateTimers()
            stopCaretBlink()
        }
    }

    override var intrinsicContentSize: CGSize {
        let labelSize = label.intrinsicContentSize
        let caretSpace = configuration.showsCaret ? configuration.caretWidth + 2 : 0
        return CGSize(width: labelSize.width + caretSpace, height: caretHeight())
    }
}

components.usage:
let label = TypewriterLabel()
view.addSubview(label)
label.cycle(["Build faster.", "Ship sooner.", "Own your code."])
